INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604234N$$, $$Advanced Hawkeye$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 350324000, 365249000, 288268000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 32, "original_pe": "0604234N", "page_header": "Department of the Navy"}$$::jsonb, $$The E-2D Advanced Hawkeye (AHE) program provides the Navy with a carrier-based airborne command and control platform, which is equipped with the APY-9 radar system, multiple communications systems for data and voice, and additional sensor systems. All of these systems are integrated into the aircraft via a computing infrastructure that is highly automated, which enables a highly trained crew of just 5 aviators to conduct battle management that would otherwise require several dozen personnel at multiple locations. E-2D is a core pillar of theater and carrier strike group air defense and is a key enabler to Joint long-range fire kill webs necessary to defeat the threats of our peer adversaries. Work has begun on upgrading the 25-year-old computing architecture of the AHE that will allow the Navy to lead the Joint All Domain Command and Control (JADC2) efforts in any theater. As production of the airplane winds down (final airframe procurement is scheduled for FY26), the threat continues to increase in both capability and capacity. The E-2D Research, Development, Test and Evaluation budget reflects the Navy's investment into the E-2D to ensure that the US maintains a tactical advantage over any adversary. Efforts initiated in recent years ensure that the E-2D can outpace the threat, and include upgrades to the air vehicle, mission systems, datalinks, and sensors. The program integrates and tests these new capabilities and provides Fleet concurrent training equipment upgrades. Subsequent to successful testing, new capabilities are delivered on a regularly scheduled basis and are put together as a Delta System/Software Configuration (DSSC) package to ensure commonality and configuration control across the Fleet. Among the other E-2D mission systems R&D efforts, there are 2 major initiatives that will ensure that the E-2D is ready & relevant into the coming decades. First, obsolete and failing components of the 15-year-old cockpit design are being addressed by HECTR (Hawkeye Cockpit Technical Refresh), which ensures a higher safety margin for carrier landings after 8-12 hour sorties and will substantially decrease sustainment costs over the lifecycle of the aircraft. Second is TCID (Theater Combat Identification), which includes upgrades to the 25 year-old computing infrastructure mentioned above. TCID will bring Multi-Level Security and Cross-Domain solutions through an Open Mission System (OMS) Architecture. TCID is the key to establishing the CNO's vision for the Naval Operational Architecture and the Joint Chiefs' vision for JADC2. HECTR and TCID are planned for DSSC-6, FY30 delivery. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                            Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System         PE 0604234N / Advanced Hawkeye Development & Demonstration (SDD) JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision.$$, NULL, 428310000, 440222000, 427300000, NULL, NULL, 118, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 295273000, 350324000, 390260000, 390260000, NULL, 390260000, 435007000, $$The E-2D Advanced Hawkeye (AHE) program provides the Navy with a carrier-based airborne command and control platform, which is equipped with the APY-9 radar system, multiple communications systems for data and voice, and additional sensor systems. All of these systems are integrated into the aircraft via a computing infrastructure that is highly automated, which enables a highly trained crew of just 5 aviators to conduct battle management that would otherwise require several dozen personnel at multiple locations. E-2D is a core pillar of theater and carrier strike group air defense and is a key enabler to Joint long-range fire kill webs necessary to defeat the threats of our peer adversaries. Work has begun on upgrading the 25-year-old computing architecture of the AHE that will allow the Navy to lead the Joint All Domain Command and Control (JADC2) efforts in any theater. As production of the airplane winds down (final airframe procurement is scheduled for FY26), the threat continues to increase in both capability and capacity. The E-2D Research, Development, Test and Evaluation budget reflects the Navy's investment into the E-2D to ensure that the US maintains a tactical advantage over any adversary. Efforts initiated in recent years ensure that the E-2D can outpace the threat, and include upgrades to the air vehicle, mission systems, datalinks, and sensors. The program integrates and tests these new capabilities and provides Fleet concurrent training equipment upgrades. Subsequent to successful testing, new capabilities are delivered on a regularly scheduled basis and are put together as a Delta System/Software Configuration (DSSC) package to ensure commonality and configuration control across the Fleet. Among the other E-2D mission systems R&D efforts, there are 2 major initiatives that will ensure that the E-2D is ready & relevant into the coming decades. First, obsolete and failing components of the 15-year-old cockpit design are being addressed by HECTR (Hawkeye Cockpit Technical Refresh), which ensures a higher safety margin for carrier landings after 8-12 hour sorties and will substantially decrease sustainment costs over the lifecycle of the aircraft. Second is TCID (Theater Combat Identification), which includes upgrades to the 25 year-old computing infrastructure mentioned above. TCID will bring Multi-Level Security and Cross-Domain solutions through an Open Mission System (OMS) Architecture. TCID is the key to establishing the CNO's vision for the Naval Operational Architecture and the Joint Chiefs' vision for JADC2. HECTR and TCID are planned for DSSC-6, FY30 delivery. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                            Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System         PE 0604234N / Advanced Hawkeye Development & Demonstration (SDD) JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0105519N$$, $$(U)Nuclear-Armed Sea-Launched Cruise Missile Spt$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 1929931000, 0, 0, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 31, "original_pe": "0105519N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 980010000, 2635909000, 1420618000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 0, 0, NULL, 0, 1086514000, $$The Department encourages additional vendor participation in the design, development, and production of alternative weapons systems to meet current and future warfighting requirements. With current major weapons systems production at capacity, the nation is looking for alternative systems to fill these gaps. The Department is implementing diverse procurement strategies to enable rapid acquisition. These will include the use of Other Transaction Authorities, 'Marketplace' acquisition platforms, and alternative concepts to increase supply and suppliers in addition to traditional FAR-based procurement strategies. The FY 2026 spend plan includes $0 thousand of discretionary and $1,677,309 thousand of reconciliation for a total of $1,677,309 thousand. The Nuclear-Armed Sea Launched Cruise Missile Program (SLCM-N) is not a new start in FY2027. No discretionary funding is requested for FY2027. SLCM-N is a theater nuclear system intended to expand the President's options for responding to limited nuclear use and strategic non-nuclear attacks. SLCM-N enables a persistent, survivable regional nuclear presence that provides assurance to U.S. allies of a credible U.S. theater nuclear response, without dependence on allied host nations. The SLCM-N program was established per the Acquisition Decision Memorandum (ADM) dated March 15, 2024. The ADM designated SLCM-N an ACAT ID Major Defense Acquisition Program with the Navy as the lead component, as well as authorized the program's entry into the Materiel Solutions Analysis phase. The SLCM-N program is planning to achieve Initial Operational Capability by 30 September 2034 per the FY2024 NDAA and Limited Operational Capability by 30 September 2032 per the FY2026 NDAA. SLCM-N Enterprise System is composed of the SLCM-N Weapon System and Integrated Product Support (IPS). It requires the aggregation of both the Weapon System and IPS to produce the required capability of the SLCM-N program. Nuclear Weapon Surety (Safety, Security, and Use Control) applies across the entire SLCM-N Enterprise System. The SLCM-N Weapon System is the composition of the flight vehicle, warhead, capsule, canister, fire control, enabling platform equipment, and multiple canister launcher that will function onboard a launch platform. SLCM-N IPS addresses respective subsystems and implementation. The scope of IPS includes the enterprise level integration aligned to DoDI_5000.91: Facilities and Infrastructure, Support Equipment, Training Activities, Packaging, Handling, Storage, and Transportation, and Sustaining Engineering. Mandatory funding supports the following SLCM-N program cost categories and corresponding efforts: Missile Systems: Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                              Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced         PE 0105519N / (U)Nuclear-Armed Sea-Launched Cruise Missile Spt Component Development & Prototypes (ACD&P) The Missile System consists of: All-Up Round (AUR), which includes: 1) Flight Vehicle and 2) Canister Multiple Canister Launcher (MCL)Missile System Integrated Product Support Subsystem, which includes: 1) Facilities and Infrastructure; 2) Support Equipment; 3) Training Activities and Equipment; and 4) Packaging, Handling, and Storage Equipment. The Missile System will be delivered to the VIRGINIA-Class submarine; each AUR, will be loaded into an MCL. The AURs and MCLs will be supported by the Missile System Integrated Product Support System, which includes facilities and infrastructure to develop, test, process and deliver the system, all common/unique support equipment, procedures, and training curriculum. The Missile System also includes all Shore CONOPS, planning activities and requirement definition for shore integration facilities and development of associated program documentation. Activities to be performed with mandatory funding include: Complete Phase 1 of competitive design and prototyping contracts for the AUR and MCL and transition to Phase 2 subsystem prototyping testing Transition from Phase 1 design and prototyping contracts for the AUR and MCL, to Phase 2 subsystem prototyping testing Conduct component testing (Software in the Loop, Hardware in the Loop) Procure hardware for developmental testing Perform prototyping and ground testing of Missile Subsystem and Launcher Subsystem components Perform detailed planning to enable future underwater launch testing and qualification prior to platform integration. Assess concept designs for Missile System components Develop and build prototype inert AURs and MCLs to support competitive launcher testing Develop and build prototype inert AURs and test equipment to support competitive flight testing Assess system performance during flight testing and assess final concepts Design missile specification and mission load interfaces ensuring validation and verification requirements meet nuclear and cyber security standards Conduct payload integration, and interface testing and analysis Coordinate with industry partners to ensure specific platform requirements (hardware, software, cybersecurity, system safety, external data sources, launcher, HMI, SWAP, etc.) are identified and integrated appropriately Initiate component-level testing, initiate launcher interface gas generator and ejector Design Developmental Test and Evaluation Conduct MCL/Canister platform interface verification planning Begin/launch sequence analysis Complete IAL campaign 1 to baseline anticipated launcher and flight vehicle launch performance Procure IAL campaign 2 and additional UWL testing long lead support equipment and test articles Fabrication of flight test hardware for IAL and UWL Plan and Design missile storage and maintenance facilities Conduct Strategic Weapon Facility Nuclear Weapon Security requirement studies Develop Special Weapon Ordnance Publications Establish SLCM-N Nuclear Weapon Accountability Program at SWFs Develop and proof shipment, storage, handling and transfer special equipment and procedures for the SWFs Perform the following subsystem level reviews: Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                   Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced             PE 0105519N / (U)Nuclear-Armed Sea-Launched Cruise Missile Spt Component Development & Prototypes (ACD&P) Flight System Requirements and Functional Review Shipboard Systems: Responsible for lifecycle ownership of the SLCM-N nuclear fire control subsystem, submarine platform systems modifications and SLCM-N engagement and mission planning. Lifecycle ownership for nuclear fire control subsystems, submarine platform systems and engagement and mission planning include hardware and software systems engineering, trade studies, design, development, modeling, simulation, test, analysis, evaluation, reporting, verification, validation, acceptance, quality control, accreditation, certification, prototyping, installation, integration, production, operations, sustainment, maintenance, technical and training tools, equipment and products. Activities to be performed with mandatory funding include: Develop nuclear fire control subsystem, submarine platform systems and mission planning requirements Develop nuclear fire control subsystem prototypes Develop nuclear fire control subsystem and submarine platform systems artifacts in support of System Requirements Review Conduct Technology Maturation and Risk Reduction efforts, nuclear fire control subsystem prototypes, submarine platform systems and mission planning Establish subsystems agreements, assess and configure laboratories and facilities in support of prototype and subsystem interface verification Develop TEMPALT configuration design for launch platforms Conduct warhead demonstration and initial fire control prototype lab integration Conduct fire control Missile Processing Tool testing Develop subsystem interface verification criteria with SSN platform leads Develop SHIPALTs and draft engineering changes Leverage Limited Operational Capability (LOC) to support Shipboard integration and develop support equipment, procedures, trainers and facility activation Test & Evaluation: Plans and executes government test activities, providing support and oversight of Developmental Test and Evaluation (DT&E) activities, advocating for Test and Evaluation capabilities gaps, managing System Integration Labs, and collecting the test data necessary to perform data-derived verification and validation of the SLCM- N weapon system. This includes the planning, management and oversight of DT&E activities while maintaining insight into contractor test activities under the program, coordination and facilitation of Operational Test and Live Fire Test and Evaluation activities. Oversee the T&E activities of other participating government entities while ensuring the coordination and completion of the Test and Evaluation Master Plan in accordance with DoD guidance. Ensures adequate T&E resources and infrastructure are available to support the SLCM-N schedule. Ensures the conduct of SLCM-N cyber security testing. Activities to be performed with mandatory funding include: Conduct system integration lab study Conduct range capabilities assessment study Develop program required T&E documentation, including Test & Evaluation Master Plan (TEMP), Test strategy, schedule and program implementation Conduct planning, provisioning and execution of subsystem, and lower, Technology Maturation and Risk reduction developmental test and evaluations efforts Coordinate with OPTEVFOR (OT&E) for development of Integrated Evaluation Framework (IEF) Conduct planning for upgrades to range infrastructure to support future missile and capabilities testing at DOD test ranges Conduct launcher interface DT/validation Execute SLCM-N Weapon System Lab activation and integration testing Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                             Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced          PE 0105519N / (U)Nuclear-Armed Sea-Launched Cruise Missile Spt Component Development & Prototypes (ACD&P) (U)Evaluating alternative warhead options that meet military requirements while minimizing impact to the existing modernization Program of Record to the greatest extent possible. Warhead Systems will coordinate with the DOE to integrate the selected WH into the Navy delivery system, certify compatibility, and provide developmental hardware, support equipment (H, T and UC gear), operational procedures, and in-service support for the WH across all lifecycle activities per DODI 5030.55. Efforts will be coordinated with DOE/NNSA through the SLCM-N Project Officers Group and in accordance with FY2025 NDAA amended language. Activities to be performed with mandatory funding include:/Complete Phase 6.2/6.2A activities and begin Phase 6.3 activities for the SLCM-N warhead to include, but not limited to: Develop, assess, and test prototype components Conduct Warhead Subsystem Requirements Review Conduct Warhead Subsystem Conceptual Design Review Conduct manufacturing Process Prove-In and Engineering Evaluation to support Engineering Authorizations for product and process development Leverage Limited Operational Capability (LOC) to support warhead integration and surety strategies and develop support equipment, procedures, trainers, and facility activation Update Technology Readiness Levels, Manufacturing Readiness Levels and production cost estimates Develop Provisioning Plan for spare components Conduct Laboratory Task Group (LTG) and Joint Task Group (JTG) reviews to validate proposed procedures Develop the Stockpile Evaluation Program Plan and Joint DOD/DOE Nuclear Weapon Subsystem Test Plan Conduct independent peer reviews to validate technical and programmatic approaches with acceptable risk Conduct Warhead Subsystem Baseline Design Review Conduct Preliminary Design Review and Acceptance Group Limited Operational Capability: Responsible for the design, development, production, test, delivery and demonstration of a SLCM-N Limited Operational Capability per the FY2026 National Defense Authorization Act (NDAA). Activities to be performed with mandatory funding include: Develop detailed SOW and POA&M to execute Demo#1 flight test Develop SOW and POA&M to execute Demo#2 flight test Conduct Demo#1 flight test Support definition of power and data availability for WIU design Support definition of mechanical interface with minimal effect on flight performance Support development and testing of WH design Develop engineering concepts and perform scientific and engineering analyses and planning to achieve stated objectives Develop top level requirements, performance specifications, and mission requirements, and establish configuration functional baselines for the system Prepare Test and Evaluation Master Plans, procedures and test packages Conduct validation and verification of simulations, software, and hardware. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                             Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced          PE 0105519N / (U)Nuclear-Armed Sea-Launched Cruise Missile Spt Component Development & Prototypes (ACD&P) Weapon Integration & Systems Engineering: Evaluates and establishes systems engineering policy for all phases of the Nuclear-Armed Sea-Launched Cruise Missile program, including overall safety, security, and program protection of the system. Manage and assess technical adequacy of SLCM-N weapon system (WS) planning and design. This includes defining SLCM-N WS technical milestones, establishing a standard process for component level reviews, and implementing weapon system-level engineering reviews. Establish system-level requirements, defining interfaces (coordination) between subsystems. Develop the overall SLCM-N WS architecture and maintain the flow down of model-based systems engineering as part of the overall systems and digital engineering strategy. Manage SLCM-N Risks, Issues and Opportunities, Decision Analysis, Digital Engineering, and Systems Engineering Control Board Processes. Implement and manage the SLCM-N Program Protection Plan, to include critical program information analysis and protection efforts. Oversee Safety, Surety, and Nuclear Weapon NW Security plans and processes. Manage all efforts associated with acquisition, documentation, contracts, financial management, logistics planning, fleet integration and Engineering Support Services/Professional Support Services (ESS/PSS) support. Activities to be performed with mandatory funding include: Provide technical program and project management of the SLCM-N program, including development and maintenance of task planning, expenditure monitoring/reporting Develop the Component Cost Estimate / Program Office Estimate, support preparation for Final Cost Review Board Develop the Acquisition Strategy and other documentation required for Gate 3 and Milestone A Develop documentation required for Milestone B Develop Integrated Master Plan (IMP) and Integrated Master Schedule Develop the Capabilities Development Document, Life Cycle Sustainment Plan and established the operational requirements, technical specifications and programmatic details of the SLCM-N program Coordinate with fleet stakeholders to develop requirements for tactical readiness, training, manpower, personnel, security, certification, documentation, publications, sustainment, maintenance, and employment Conduct Platform System Requirements Review and initiate Platform Preliminary Design Review Develop Verification & Validation Plan, Anti-Tamper Plan, and Modeling & Simulation Strategy Conduct safety, surety, and nuclear weapon security coordination Maintain risk/opportunity tracking, digital engineering, and decision analysis processes Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                    Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced      PE 0105519N / (U)Nuclear-Armed Sea-Launched Cruise Missile Spt Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303354N$$, $$ASW Systems Development - MIP$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 3864000, 10167000, 7253000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 31, "original_pe": "0303354N", "page_header": "Department of the Navy"}$$::jsonb, $$Airborne ASW Intelligence (AAI) (CNO Project K-0416) provides advanced Anti-Submarine Warfare (ASW) capabilities through development of new technology and prototype mechanisms for the collection and analysis of ASW related intelligence. This includes full spectrum intelligence collections, analysis, and cataloging of current peer and near peer adversaries. The program develops and deploys disruptive technologies to counter emerging threats in order to maintain the United States' current undersea warfare superiority. AAI employs systems such as the Mighty Orion (MO) and Anti-Submarine Warfare Mission Planning and Reconstruction Systems (AMPRS) with the Global Reconstruction and Acoustic Measurement Suite (GRAMS) software application to support the Tasking, Collection, Processing, Exploitation, and Dissemination (TC/PED) of passive and active intelligence measurements of current and next generation submarine vulnerabilities. The AAI data collection program provides full spectrum, measured intelligence data essential for the design and development of advanced sensors, weapon systems, environmental models, and tactical decision aids by using currently fielded sonobuoy systems; developing the Passive Extended Range Sonobuoy System (PERSS) and providing support for completion of the AN/SSQ-113 Naval Underwater Active Multi-ping (NUAMP) family of sensors to collect active target strength measurement (ATSM) data for the Intelligence Community. AAI collection systems are installed and employed on uniquely configured platforms, specially configured ground support facilities, ships, and other assets as required for the collection, processing, exploitation, and dissemination of undersea intelligence. AAI develops advanced components and system prototypes for advanced detection and tracking systems, specially designed sensors, advanced processing systems and techniques, and specially derived tactics. This is a Military Intelligence Program (MIP). JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under ADVANCED COMPONENT DEVELOPMENT AND PROTOTYPES because it includes all efforts necessary to evaluate integrated technologies, representative models or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced         PE 0303354N / ASW Systems Development - MIP Component Development & Prototypes (ACD&P)$$, NULL, 3454000, 3543000, 3564000, NULL, NULL, 104, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 7253000, 3864000, 3206000, 3206000, NULL, 3206000, 3670000, $$Airborne ASW Intelligence (AAI) (CNO Project K-0416) provides advanced Anti-Submarine Warfare (ASW) capabilities through development of new technology and prototype mechanisms for the collection and analysis of ASW related intelligence. This includes full spectrum intelligence collections, analysis, and cataloging of current peer and near peer adversaries. The program develops and deploys ASW technologies to counter emerging threats in order to maintain the United States' current undersea warfare superiority. AAI employs systems such as the Mighty Orion (MO) and Anti-Submarine Warfare Mission Planning and Reconstruction Systems (AMPRS) with the Global Reconstruction and Acoustic Measurement Suite (GRAMS) software application to support the Tasking, Collection, Processing, Exploitation, and Dissemination (TC/PED) of passive and active intelligence measurements of current and next generation submarine vulnerabilities. The AAI data collection program provides full spectrum, measured intelligence data essential for the design and development of advanced sensors, weapon systems, environmental models, and tactical decision aids by using currently fielded sonobuoy systems; and providing support to collect active target strength measurement (ATSM) data for the Intelligence Community. AAI collection systems are installed and employed on uniquely configured platforms, specially configured ground support facilities, ships, and other assets as required for the collection, processing, exploitation, and dissemination of undersea intelligence. AAI develops advanced components and system prototypes for advanced detection and tracking systems, specially designed sensors, advanced processing systems and techniques, and specially derived tactics. This is a Military Intelligence Program (MIP). JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under ADVANCED COMPONENT DEVELOPMENT AND PROTOTYPES because it includes all efforts necessary to evaluate integrated technologies, representative models or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                       Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced        PE 0303354N / ASW Systems Development - MIP Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L075$$, $$Communications Items under $5M$$, $$proc_navy_1810_ba2$$, $$peo_c4i$$, 2026, 11493000, 6641000, 6709000, NULL, $${"page": 100, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "75", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 70", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 3435, "p1_line_num": 70, "fy27_total_K": 3435}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 3687, "li_num": 70, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 11493000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 9209000, 11138000, 3435000, 3435000, 0, 3435000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604282N$$, $$NEXT GENERATION JAMMER (NGJ) INC II$$, $$rdte_navy_ba5$$, $$peo_mles$$, 2026, 228256000, 154229000, 147091000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 32, "original_pe": "0604282N", "page_header": "Department of the Navy"}$$::jsonb, $$The Next Generation Jammer (NGJ) is the next step in the evolution of Airborne Electronic Attack (AEA) and is a critical capability necessary to address current, emerging, and evolving Electronic Warfare gaps, ensure kill chain wholeness against growing threat capabilities and capacity, keep pace with enemy threat weapon systems' advancements, and support the continuous expansion of the AEA mission areas that exceed the capability of currently fielded systems. NGJ will utilize enhanced techniques and tactics to deliver significantly improved radar and communications jamming effectiveness as well as other classified capabilities. Utilizing an Open Systems Architecture that supports software and hardware updates to rapidly counter emergent and evolving threats, NGJ is a key enabler and force multiplier for operations across the spectrum of missions defined in the Defense Strategic Guidance, including strike warfare, projecting power despite highly contested environments, and counterinsurgency/irregular warfare. NGJ will also address the shortfalls in scalability, flexibility, supportability, interoperability, availability, and capability of the existing AN/ALQ-99 Tactical Jamming System. This Program Element (PE 0604282N) supports the AN/ALQ-266 Next Generation Jammer - Low Band (NGJ-LB) (formerly known as Next Generation Jammer Increment 2) program. NGJ-LB will address AEA capability and sufficiency gaps against enemy threats operating in the lower frequency bands of the electromagnetic spectrum. NGJ-LB will provide the ability to effectively engage enemy threats from increased stand-off distances, employ increased capacity (number of jamming assignments) against enemy targets, and support agile employment by operators and increases survivability and lethality of 4th and 5th generation platforms and strike weapons. The NGJ-LB system will be integrated on the EA-18G tactical aircraft and will augment and then replace the legacy AN/ALQ-99 Tactical Jamming System in the low band frequencies. NGJ-LB is a Cooperative development program with Australia.$$, NULL, 547068000, 456609000, 252574000, NULL, NULL, 128, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 142651000, 215256000, 497011000, 497011000, NULL, 497011000, 122869000, $$The Next Generation Jammer (NGJ) is the next step in the evolution of Airborne Electronic Attack (AEA) and is a critical capability necessary to address current, emerging, and evolving Electronic Warfare gaps, ensure kill chain wholeness against growing threat capabilities and capacity, keep pace with enemy threat weapon systems' advancements, and support the continuous expansion of the AEA mission areas that exceed the capability of currently fielded systems. NGJ will utilize enhanced techniques and tactics to deliver significantly improved radar and communications jamming effectiveness as well as other classified capabilities. Utilizing an Open Systems Architecture that supports software and hardware updates to rapidly counter emergent and evolving threats, NGJ is a key enabler and force multiplier for operations across the spectrum of missions defined in the Defense Strategic Guidance, including strike warfare, projecting power despite highly contested environments, and counterinsurgency/irregular warfare. NGJ will also address the gaps in scalability, flexibility, supportability, interoperability, availability, and capability of the existing AN/ALQ-99 Tactical Jamming System. This Program Element (PE 0604282N) supports the AN/ALQ-266 Next Generation Jammer Low Band (NGJ-LB) (formerly known as Next Generation Jammer Increment II) program. NGJ-LB will address AEA capability and sufficiency gaps against enemy threats operating in the lower frequency bands of the electromagnetic spectrum. NGJ-LB will provide the ability to effectively engage enemy threats from increased stand-off distances, employ increased capacity (number of jamming assignments) against enemy targets, and support agile employment by operators and increases survivability and lethality of 4th and 5th generation platforms and strike weapons. The NGJ-LB system will be integrated on the EA-18G tactical aircraft and will augment and then replace the legacy AN/ALQ-99 Tactical Jamming System in the low band frequencies. NGJ-LB is a Cooperative development, production and sustainment program with Australia. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                             Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System           PE 0604282N / NEXT GENERATION JAMMER (NGJ) INC II Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0204575N$$, $$Elect Warfare Readiness Supt$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 115834000, 65284000, 229164000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 38, "original_pe": "0204575N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 289570000, 88845000, 96689000, NULL, NULL, NULL, NULL, NULL, FALSE, 220689000, 115834000, 198560000, 198560000, NULL, 198560000, 98542000, $$The details of this budget justification are classified, per Executive Order 13526, Sec 1.4 (a) and are submitted annually to Congress in the classified budget justification book.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606942N$$, $$Assessments & Evals Cyber Vulnerabilities$$, $$rdte_navy_ba6$$, $$navair$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 13885000, 14555000, 14754000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 11282000, 11282000, NULL, 11282000, 15031000, $$NAVY CYBERSECURITY Cyber Warfare consists of many different aspects to include sabotage of our weapon systems, networks as well as enablement of missions. Nation and non-nation state actors are acquiring and employing more advanced cyber-attacks in order to exploit our networks and aviation systems challenging our technological edge. The threats and capabilities are real and range from exploiting capabilities, overloading weapons systems and logistics supply chains, to jamming signals or taking control of weapons systems. Adversarial cyber-attacks must be defended against while contributing to the exploitation of cyber warfare capabilities. To meet these challenges and address the Chief of Naval Operations priorities and tasking, these efforts are specifically focused on Naval Air Systems Command weapon or control systems and programs to ensure warfighting effectiveness as part of integrated / multi-platform kill chains. These efforts will strengthen our cyber posture by developing capabilities and solutions to deter, detect, and mitigate cyber threats and safeguard classified naval aviation systems and platforms from "cradle to grave." These solutions will be integrated into the acquisition of weapons systems to enhance security, increase lethality, and improve resiliency in the expected operational environments. Our weapon or control systems are unique in the aforementioned environments and mission, but also in the presence of numerous non- traditional access points and trusted cyber relationships required for operational environments. Further, this line sustains Naval Aviation's Red Team capability to research, identify and validate nation-state exploitable cyber susceptibilities and vulnerabilities in both deployed and next-generation warfighting platforms. Through it, these efforts improve Naval Aviation's mission survivability by developing and demonstrating operational TTPs within the cyber contested environment. The team partners with Naval Aviation programs to certify theorized cyber weaknesses and thus to prevent denial, degradation or disruption of safety, readiness, and mission. The Red Team's assessment products support CYBERSAFE assessments of platforms and systems and likewise supports PMAs and OPNAV with validated threat data prioritizing systems security engineering (SSE) investments. The team leverages national-level cyber warfare experts, all-source intelligence, and technology research to assess Naval Aviation Enterprise system and system-of-system. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under RESEARCH, DEVELOPMENT, TEST and EVALUATION MANAGEMENT SUPPORT because it supports efforts directed toward sustaining or modernizing installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                       Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 6: RDT&E          PE 0606942N / Assessments & Evals Cyber Vulnerabilities Management Support$$, $$Budget J-Books/FY27/Navy/RDTEN_BA6_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0909980N$$, $$Judgment Fund Reimbursement$$, $$rdte_navy_ba6$$, $$asn_rda$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, FALSE, 181000, 0, 0, 0, NULL, 0, 0, $$Judgment Fund Reimbursement$$, $$Budget J-Books/FY27/Navy/RDTEN_BA6_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0909999N$$, $$Cancelled Account Adjustments$$, $$rdte_navy_ba6$$, $$asn_rda$$, 2026, 0, 6741000, 0, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "navy", "page_num": 37, "original_pe": "0909999N", "page_header": "Department of the Navy"}$$::jsonb, $$Cancelled Account adjustments$$, NULL, 0, 0, 0, NULL, NULL, 206, $$RDTEN_BA6_Book.pdf$$, NULL, FALSE, 2032000, 0, 0, 0, NULL, 0, 0, $$Cancelled account adjustments.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA6_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207161N$$, $$Tactical Aim Missiles$$, $$rdte_navy_ba7$$, $$navy_cno$$, 2026, 34650000, 35502000, 31359000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 38, "original_pe": "0207161N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 105264000, 106310000, 106666000, NULL, NULL, NULL, NULL, NULL, FALSE, 30668000, 34650000, 122518000, 122518000, NULL, 122518000, 108790000, $$The AIM-9X Block II Sidewinder (AIM-9X Blk II) continues the evolution of the AIM-9 series of missiles. This missile program delivers a launch and leave, air combat munition that uses passive Infrared (IR) energy to acquire and track enemy air targets and complements the radar guided Advanced Medium Range Air-to-Air Missile (AMRAAM). The missile provides fighter aircrew with the first shot, first kill opportunities that are essential for survival during air combat maneuvering in the visual arena. The AIM-9X delivers these opportunities with unmatched offensive and defensive capabilities against inner boundary threats, even when IR countermeasures are employed. The AIM-9X also supports air superiority in the Beyond Visual Range air-to-air battle. Anti-tamper features have been incorporated to protect improvements inherent in this design. The AIM-9X Block II missile provides the Joint Force with fighter aircraft lethality and survivability necessary to counter threats identified in the Chief of Naval Operations Guidance and National Defense Strategy. AIM-9X is a Post Milestone C, Acquisition Category IC joint service program led by the Department of the Navy. The Block II program has completed independent operational testing and was found to be operationally effective and suitable. The program achieved Navy Initial Operational Capability in March 2015 and received Full Rate Production decision in August 2015. This budget line item continues technical refresh of hardware and software and develops advanced capabilities to meet requirements of the Capability Production Document against evolving threat aircraft countermeasures. The AIM-9X Compact Variant (AIM-9X CV) repackages the AIM-9X Blk II technology into a compact airframe optimized for internal carriage on advanced aircraft with improved kinematic performance. The program will deliver increased capability to the warfighter with greater standoff range, increased aircraft weapon station capacity, and maintains inner boundary performance. This program is funded under OPERATIONAL SYSTEMS DEVELOPMENT because it includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational       PE 0207161N / Tactical Aim Missiles Systems Development$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0206313M$$, $$Marine Corps Comms Systems$$, $$rdte_navy_ba7$$, $$mc$$, 2026, 125488000, 154911000, 150050000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "mc", "page_num": 38, "original_pe": "0206313M", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 181736000, 151454000, 148432000, NULL, NULL, NULL, NULL, NULL, FALSE, 139757000, 128384000, 268983000, 268983000, NULL, 268983000, 154150000, $$This program element provides funding to develop command and control (C2) support and information infrastructures for the Fleet Marine Force and supporting establishment. Doctrinally, the C2 support system and the information infrastructure form two parts of a triad of capabilities which permit command and control systems to be transformed into a complete operating system. The third element of the triad is command and control organization and is not covered in this program element. USMC command and control is divided into seven functional areas and one supporting functional area as follows: intelligence C2, fire support C2, air operations C2, radio systems C2, combat service support C2, warfare C2, radar systems C2, and C2 support (information processing and communications). Within this program element, subprojects have been grouped by C2 functional area for more efficient planning. Air defense weapons systems have been added to facilitate planning, and a separate project is used for systems assigned to the supporting establishment. Subprojects which support the Commander's decision Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                              Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational    PE 0206313M / Marine Corps Comms Systems Systems Development processes have been collected into the Command Post Systems project since these systems must work in close cooperation to ensure effective C2 of Marine Air Ground Task Forces. The FY 2025 spend plan amount for Marine Corps Tactical Radio Systems, Signature Management (SIGMAN) includes $2,010 thousands of discretionary and $7,030 thousands of mandatory (reconciliation) for a total of $9,040 thousands.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0308601N$$, $$Modeling & Simulation Support$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 12389000, 10665000, 20927000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 39, "original_pe": "0308601N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 15465000, 15230000, 14668000, NULL, NULL, NULL, NULL, NULL, FALSE, 20253000, 23973000, 16401000, 16401000, NULL, 16401000, 14945000, $$This Program Element supports activities and projects conducted by the Navy Modeling and Simulation (M&S) Office (NMSO). It enables technical and management initiatives that bring organization, focus, and efficiency to the development and use of M&S throughout the Navy and the Department of the Navy (DoN). NMSO provides a central organization for the formulation and implementation of policy and guidance in M&S and represents Navy interests in Department of War (DoW), Joint, and other agency initiatives. It funds efforts to define and coordinate Enterprise Navy M&S policy, execution, and guidance to evolve an interoperable and reusable core M&S capability consistent with the DoW's technical frameworks across the Future Years Defense Program (FYDP). Navy M&S priorities include interoperability and composability, effective capability use and reuse, and the incorporation of Model Based Systems Engineering (MBSE) products to help determine the networks, infrastructure, and data needed to support Enterprise Navy M&S capabilities. These leverage M&S standards, information systems, live virtual constructive environments, and collaborative design and development systems that support analysis, acquisition, training, and warfighting decision- making. NMSO's efforts are organized around three product areas: (1) Core Services: This activity provides leadership and essential planning, program and financial management, and execution of NMSO efforts as well as coordination with the other Services, the Office of Secretary of War (OSW), the Joint Staff, and other agencies. It also oversees initiatives to develop, promulgate, and track the policies and procedures necessary to support the creation of a robust and credible capability to create synthetic environments, accurately represent platforms and systems, predict outcomes, and provide inputs to Naval decision-makers and operational users. (2) Community Services: This activity provides M&S community-wide services, digital ecosystems, and technical exchanges; M&S plans and standards; and verification, validation, and accreditation (VV&A) handbooks and codes of best practice. It also develops M&S procurement guidance, digital engineering strategic goals, and supports M&S discovery and reuse capabilities across the DoN and Navy M&S communities. (3) Community Experiments and Prototypes: This activity develops and executes experiments and prototypes focused on the advancement of M&S capabilities and technologies to increase M&S efficiency and effectiveness in its application across the Navy Enterprise. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                           Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational    PE 0308601N / Modeling & Simulation Support Systems Development$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602384BP$$, $$Chemical and Biological Defense Program$$, $$rdte_dw_ba2$$, $$dw_cbdp$$, 2026, 230751000, 235871000, 224777000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "dw", "page_num": 67, "original_pe": "0602384BP", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 183139000, 173683000, 171682000, NULL, NULL, NULL, NULL, NULL, FALSE, 223843000, 204055000, 207186000, 207186000, 0, 207186000, 169149000, $$This program element (PE) resources Applied Research across the Understand, Protect, Mitigate, and Enabling Investments portfolios. Chemical and Biological Defense Program (CBDP) investments provide an integrated, layered capability to enable Department of War (DoW) missions in a chemical and biological environment, ranging from combat operations to domestic incident prevention and response. The Projects in this PE support applied research in the areas of physical technologies, non-traditional agent (NTA) medical and physical defense technologies, and medical technologies. These investments are a key component to sustaining the core physical and intellectual chemical and biological (CB) defense infrastructure of the Department and support the delivery of capabilities, assessments of emerging threats, and the ability to surge unique capabilities in response to a CB event. FY 2027 funding accelerates characterization and situational awareness of emerging biothreats and accelerates delivery of improved protection from and mitigation of biothreats, including rapid repurposing of available therapeutics and development of new vaccines. Individual Projects include: - Understand (UN2): Development of next-generation chemical and biological hazard detectors, point-of-need diagnostic devices, next-generation diagnostics systems, decision support tools, algorithms, and software. - Protect (PT2): Development of antidotes, disease surveillance medical technologies, vaccines, nerve agent pretreatments, individual protection materials, and respiratory and ocular protection. Improvement of protection technologies and biological weapon/agent surveillance. - Mitigate (MT2): Improvement of CB defense material, including contamination avoidance and decontamination. Development of drug treatments, therapeutics, patient decontamination technologies, and individual protection advancements. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Chemical and Biological Defense Program                                            Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:              PE 0602384BP / Chemical and Biological Defense Program Applied Research - Enabling Investments (EN2): Characterization of safety/efficacy models and microphysiological models that mimic the human response to biological and chemical agents. Development and addition of physical and intellectual infrastructure capabilities to conduct defensive classified Department of War (DoW) work in laboratories. Execution of a robust emerging biothreat portfolio to enable readiness for future incidents. CBDP Science and Technology (S&T) Applied Research Performers: U.S. Army Combat Capabilities Development Command Chemical Biological Center (DEVCOM CBC), United States Army Medical Research Institute of Infectious Diseases (USAMRIID), United States Army Medical Research Institute of Chemical Defense (USAMRICD), United States Army Natick Soldier Systems Center, Naval Research Lab (NRL), Air Force Research Lab (AFRL), and Department of Energy Laboratories such as Pacific Northwest National Laboratory (PNNL), among others. The intent is to maintain strategic partnerships with the DoW Service communities & the interagency for mission success across the enterprise through collaborative planning and programming maintaining budget assurance. Efforts under this PE will transition to or will provide risk reduction for Advanced Technology Development (PE 0603384BP), Advanced Component Development and Prototypes (PE 0603884BP), and System Development and Demonstration (PE 0604384BP) activities.$$, $$Budget J-Books/FY27/DW/RDTE_CBDP_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0208097JCY$$, $$Cyber Command and Control (C2)$$, $$rdte_dw_ba7$$, $$dw$$, 2026, 85833000, 95733000, 96932000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 79, "original_pe": "0208097JCY", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 86913000, 88600000, 90717000, NULL, NULL, NULL, NULL, NULL, FALSE, 96932000, 85833000, 85958000, 85958000, NULL, 85958000, 92531000, $$Dominance in cyberspace requires commanders to visualize the battlespace, make informed decisions faster than the adversary, and direct forces with precision. Joint Cyber Command and Control (JCC2) provides the integrated situational awareness, planning, and battle management capabilities required to achieve these outcomes. As a congressionally directed effort, JCC2 serves as the Department’s focal point for unifying cyber Command and Control (C2) across all echelons, enabling seamless coordination between Cyber Mission Forces (CMF), Combatant Commands, and joint, coalition, and interagency partners. The modern cyber environment is characterized by speed, complexity, and the convergence of operations across domains. Legacy and disconnected C2 systems cannot meet today’s operational tempo. JCC2 addresses this gap by delivering a single, integrated cyber C2 framework that ensures all stakeholders operate from a shared, authoritative operational picture. By synchronizing cyber C2 with joint and coalition C2 systems, JCC2 enhances multi‑domain operations, reduces planning timelines, improves decision quality, and shortens the kill chain. These capabilities directly support the evolving mission requirements of CMF teams conducting cyberspace operations. To maintain pace with rapidly evolving threats and operational demands, JCC2 employs a Continuous Integration/Continuous Delivery (CI/CD) development model. This approach accelerates prototyping, software development, integration of lab‑developed capabilities, and rigorous testing and evaluation. JCC2 activities include program management, studies and analysis, pilots and demonstrations, risk‑reduction efforts for emerging technologies, and the development and assessment of operational systems aligned to validated capability requirements. JCC2 is funded under Budget Activity 7, Operational System Development, reflecting its focus on upgrading, enhancing, and integrating systems that have been fielded or approved for full‑rate production. This budget request supports critical development efforts to ensure warfighters have the most advanced, interoperable, and effective cyber C2 capabilities available. Continued investment in JCC2 is essential to maintaining the nation’s competitive advantage in cyberspace, enabling the CMF to deter, disrupt, and defeat cyber threats in defense of U.S. national interests. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 United States Cyber Command                                           Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:       PE 0208097JCY / Cyber Command and Control (C2) Operational Systems Development$$, $$Budget J-Books/FY27/DW/RDTE_CYBERCOM_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602234D8Z$$, $$Lincoln Laboratory Research Program$$, $$rdte_dw_ba2$$, $$dw$$, 2026, 11479000, 45097000, 47528000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "dw", "page_num": 66, "original_pe": "0602234D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department's initiative to Build Sustainable and Long-Term Advantage. The MIT Lincoln Laboratory (MIT LL) research program element is focused on advanced technology research and development effort conducted through a cost reimbursable contract with the Massachusetts Institute of Technology (MIT). The MIT LL project supports innovative, multi-disciplined research that addresses critical national security problems. The project funds innovations that directly lead to the development of new system concepts, technologies, components, and materials in support of Department of Defense (DoD) missions. As of FY 2023, the program element funds nine technology areas. Of the nine areas, five are core-technology areas, three are emerging-technology initiatives and one Integrated Systems technology area. The four core-technology areas are Advanced Devices; Optical Systems and Technology; Information, Computation and Exploitation Sciences, Radio-Frequency (RF) Systems and Technologies, and Cyber Security Science and Engineering. The three emerging-technology areas are Advanced Materials and Processes; Quantum System Sciences; and Autonomous Systems. The one Integrated Systems technology area focuses on combining novel component-level technologies to create system-level technology solutions for important DoD problems. These technology areas provide critical capabilities that support all DoD mission areas pursued at the Laboratory. The categories are selected in consultation with the Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)) aligned with the DoD Communities of Interest (CoIs), and with guidance from other DoD agencies to address technology as well as system needs. The research in these categories adapts to solve emerging DoD problems as well as long-standing problems to which new technology advances can be applied. The individual efforts in each area are selected with the goal of enhancing DoD capabilities significantly, rather than incrementally. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                         Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:       PE 0602234D8Z / Lincoln Laboratory Research Program Applied Research$$, NULL, 10451000, 10563000, 10323000, NULL, NULL, 18, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 45822000, 46870000, 10045000, 10045000, NULL, 10045000, 10109000, $$This program supports the Department's initiative to Build Sustainable and Long-Term Advantage. The MIT Lincoln Laboratory (MIT LL) research program element is focused on advanced technology research and development effort conducted through a cost reimbursable contract with the Massachusetts Institute of Technology (MIT). The MIT LL project supports innovative, multi-disciplined research that addresses critical national security problems. The project funds innovations that directly lead to the development of new system concepts, technologies, components, and materials in support of Department of War (DoW) missions. As of FY 2023, the program element funds nine technology areas. Of the nine areas, five are core-technology areas, three are emerging-technology initiatives and one Integrated Systems technology area. The four core-technology areas are Advanced Devices; Optical Systems and Technology; Information, Computation and Exploitation Sciences, Radio-Frequency (RF) Systems and Technologies, and Cyber Security Science and Engineering. The three emerging-technology areas are Advanced Materials and Processes; Quantum System Sciences; and Autonomous Systems. The one Integrated Systems technology area focuses on combining novel component-level technologies to create system-level technology solutions for important DoW problems. These technology areas provide critical capabilities that support all DoW mission areas pursued at the Laboratory. The categories are selected in consultation with the Office of the Under Secretary of War for Research and Engineering (OUSW(R&E)) aligned with the DoW Communities of Interest (CoIs), and with guidance from other DoW agencies to address technology as well as system needs. The research in these categories adapts to solve emerging DoW problems as well as long-standing problems to which new technology advances can be applied. The individual efforts in each area are selected with the goal of enhancing DoW capabilities significantly, rather than incrementally. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                             Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:         PE 0602234D8Z / Lincoln Laboratory Research Program Applied Research$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602751D8Z$$, $$Software Engineering Institute (SEI) Applied Research$$, $$rdte_dw_ba2$$, $$dw$$, 2026, 8883000, 10535000, 11310000, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "dw", "page_num": 67, "original_pe": "0602751D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department's initiative to Build Sustainable and Long-Term Advantage. The Carnegie Mellon University Software Engineering Institute (SEI) Federally Funded Research and Development Center (FFRDC) was established in 1984 as an integral part of the DoD’s initiative to identify, evaluate, and transition software engineering technologies and practices. The mission of the SEI is to provide the DoD with technical leadership and innovation through research and development to advance the practice of software engineering and technology. The SEI works across government, industry, and academia to improve the state of software engineering from the technical, acquisition, and management perspectives. The SEI engages in research and development of critical software technologies and tools and collaborates with the larger software engineering research community. It facilitates the rapid transition of software engineering technologies into practice and evaluates emerging software engineering technologies to determine their potential for improving software-intensive Department of Defense (DoD) systems. Since its inception, the SEI has helped to transform the fields of software engineering and acquisition, network security, real-time systems, software architectures, and software-engineering process management. Software is critical to meeting the Department of Defense's (DoD) increasing demand for national defense systems that are high quality, affordable, and deployed in a timely way. With growing global parity in software engineering, the DoD must maintain leadership in all aspects of software-based system development, operation, defense, and evolution to avoid strategic surprise. To assist the DoD in retaining a long-term differential advantage over potential adversaries, the Software Engineering Institute (SEI) Applied Research program element (PE) develops and evaluates the feasibility and practicality of software and computer science concepts, with the potential to improve future DoD systems. The research conducted by this PE directly benefits the technical domains Autonomous Systems and Artificial Intelligence (AI), Cyber, and Engineered Resilient Systems. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                         Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:        PE 0602751D8Z / Software Engineering Institute (SEI) Applied Research Applied Research$$, NULL, 5263000, 3440000, 1627000, NULL, NULL, 29, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 10896000, 8758000, 7069000, 7069000, NULL, 7069000, 0, $$This program supports the Department's initiative to Build Sustainable and Long-Term Advantage. The Carnegie Mellon University Software Engineering Institute (SEI) Federally Funded Research and Development Center (FFRDC) was established in 1984 as an integral part of the DoW’s initiative to identify, evaluate, and transition software engineering technologies and practices. The mission of the SEI is to provide the DoW with technical leadership and innovation through research and development to advance the practice of software engineering and technology. The SEI works across government, industry, and academia to improve the state of software engineering from the technical, acquisition, and management perspectives. The SEI engages in research and development of critical software technologies and tools and collaborates with the larger software engineering research community. It facilitates the rapid transition of software engineering technologies into practice and evaluates emerging software engineering technologies to determine their potential for improving software-intensive Department of War (DoW) systems. Since its inception, the SEI has helped to transform the fields of software engineering and acquisition, network security, real-time systems, software architectures, and software-engineering process management. Software is critical to meeting the Department of War's (DoW) increasing demand for national defense systems that are high quality, affordable, and deployed in a timely way. With growing global parity in software engineering, the DoW must maintain leadership in all aspects of softwarebased system development, operation, defense, and evolution to avoid strategic surprise. To assist the DoW in retaining a long-term differential advantage over potential adversaries, the Software Engineering Institute (SEI) Applied Research program develops and evaluates the feasibility and practicality of software and computer science concepts, with the potential to improve future DoW systems. The research conducted by this program directly benefits the technical domains Autonomous Systems and Artificial Intelligence (AI), Cyber, and Engineered Resilient Systems. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:         PE 0602751D8Z / Software Engineering Institute (SEI) Applied Research Applied Research$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L128$$, $$Ship Missile Support Equipment$$, $$proc_navy_1810_ba4$$, $$peo_iws$$, 2026, 107709000, 92371000, 98921000, NULL, $${"page": 105, "ba_num": "04", "source": "p1_fy26", "ba_name": "Ordnance support equipment", "line_no": "128", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "04", "appr": "OPN", "title": "P-1 Line 105", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 431069, "p1_line_num": 105, "fy27_total_K": 431069}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 107709, "li_num": 106, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA4_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 107709000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 431830000, 527292000, 431069000, 431069000, 0, 431069000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603121D8Z$$, $$SO/LIC Advanced Development$$, $$rdte_dw_ba3$$, $$dw_solic$$, 2026, 0, 1951000, 5176000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 68, "original_pe": "0603121D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$FY26 SO/LIC Advanced Development has been realigned into the CTTS 122. No funds in FY26 and out. This program supports the Department's initiatives to Deter Aggression, Defend the Homeland, and Build Sustainable and Long-Term Advantage. The Advanced Development (AD) subgroup within IWTSD built on lessons learned from more than a decade of developing, managing, and overseeing the Secure Unclassified Network (SUNet) and is now developing, testing, and delivering advanced tools and capabilities for the Department of Defense (DoD) to campaign in and through cyberspace, maximize cyber capabilities in support of integrated deterrence, and effectively use cyber operations to generate asymmetric advantages. The AD subgroup streamlines the implementation and validation of Artificial Intelligence and cybersecurity requirements across IWTSD’s project portfolio as well as develops novel tools and capabilities in collaboration with our partners across the cyber domain.$$, NULL, NULL, NULL, NULL, NULL, NULL, 36, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 4987000, 0, NULL, NULL, NULL, NULL, NULL, $$FY26 SO/LIC Advanced Development has been realigned into the CTTS 122. No funds in FY26 and out. This program supports the Department's initiatives to Deter Aggression, Defend the Homeland, and Build Sustainable and Long-Term Advantage. The Advanced Development (AD) subgroup within IWTSD built on lessons learned from more than a decade of developing, managing, and overseeing the Secure Unclassified Network (SUNet) and is now developing, testing, and delivering advanced tools and capabilities for the Department of War (DoW) to campaign in and through cyberspace, maximize cyber capabilities in support of integrated deterrence, and effectively use cyber operations to generate asymmetric advantages. The AD subgroup streamlines the implementation and validation of Artificial Intelligence and cybersecurity requirements across IWTSD’s project portfolio as well as develops novel tools and capabilities in collaboration with our partners across the cyber domain.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603122D8Z$$, $$Combating Terrorism Technology Support$$, $$rdte_dw_ba3$$, $$dw_socom$$, 2026, 81513000, 168200000, 199139000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 68, "original_pe": "0603122D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$The Irregular Warfare Technical Support Directorate (IWTSD) conducts rapid research and development (R&D) in support of the Interim National Defense Strategic Guidance (INDSG) to provide leap-ahead technologies focused on surpassing current and expected levels of technology used and developed by our adversaries, with China as the pacing threat. IWTSD is mandated and structured to rapidly fill capability gaps, to include increasing lethal capability of U.S. forces at the squad and small unit level; developing lethal drones; countering small uncrewed aerial systems (drones); subterranean detection and operations; novel body and vehicle armor; detecting, protecting against, and mitigating novel and wartime CBRNE threats; telematics; covert communications; and of special interest, the use of machine learning and artificial intelligence to enhance the capability of systems used by the military and lessen the workload on the individual users. During FY 2025 and into FY 2026, IWTSD will continue to focus its R&D activities to rapidly fill the immediate, emerging, and critical capability gaps for those at the tactical edge to include our nation’s special operations forces, other military operators, intelligence analysts, and first responders. The number of capability gaps IWTSD can address are reduced due to the increased cost of incorporating artificial intelligence, machine learning, cyber hardening, and DoD safety testing of prototype systems prior to operational test and evaluation (OT&E). For instance, the focus on increased lethality has driven up costs to meet Defense safety and testing requirements. From a broader perspective, projects remain distributed among 11 mission subgroups: • Advanced Analytics • Advanced Development • Chemical, Biological, Radiological, Nuclear, and Explosives • Expeditionary Force Protection • Explosive Ordnance Disposal and Explosive Operations • Human Performance and Training • Indirect Influence and Competition • Innovation • Protection, Survivability, and Recovery • Surveillance, Collection, and Operations Support • Tactical Offensive Support Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                Date: June 2025 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:                PE 0603122D8Z / Combating Terrorism Technology Support Advanced Technology Development (ATD) To accommodate shifting emphasis in mission while still operating within budget, IWTSD eliminated the Forensics, Exploitation and Identity Management subgroup and added the Advanced Development subgroup. To place greater emphasis on the Congressionally directed joint RDT&E programs with Israel, 100% of the staff in the Expeditionary Force Protection and the Protection, Survivability, and Recovery subgroups are supporting the subterranean detection and operations and countering unmanned aerial vehicles joint programs. Lastly, the Innovation subgroup was created in anticipation of the Congressionally directed joint RDT&E Emerging Technology program with Israel. Each of the 11 subgroups have enduring R&D partnerships with USSOCOM and its components, the Services, and many Defense agencies. During FY 2024, IWTSD partnered with USSOCOM, the Services, and Defense agencies to transition or commit to transition over 12 products to a Program of Record, provided 42 prototypes to users for OT&E; commercialized 5 products, placed 2 products on a GSA/DLA catalogue, and 13 products are advancing future scientific research. IWTSD’s International R&D program has helped other DoD Components and organizations initiate task plans, which support execution of over about $60 million dollars to rapidly develop and prototype new technology and innovation through collaboration and cost sharing with Israel. While supporting the INDSG by filling capability gaps to address our adversaries, the IWTSD program will continue to identify capabilities to combat terrorism and irregular adversaries, and quickly deliver these capabilities to U.S. Defense, interagency, and international partners through rapid research and development, advanced studies, and technical innovation. IWTSD is unique in its approach, annually obtaining joint requirements directly from major Commands, Services, military operators, intelligence analysts, and first responders, and discussing those requirements with industry before the requirements are released in Broad Agency Announcements (BAA). The FY 2026 Program Requirements Meetings took place in January 2025 and contract awards will begin in early FY 2026. The IWTSD manages approximately 250 new and continuing projects, 170 of which are tied to international task plans, while also reviewing proposals and negotiating contracts for another 40 requirements for the next fiscal year. The IWTSD program, justified in the R-2 exhibit, identifies the projects that are fully or partially funded by Congressional appropriations for the IWTSD program. However, IWTSD also develops technology and provides support using external funds provided by other DoD, federal departments and international partnerships. These external funds are not reflected in this R-2 justification. However, the number of activities does reflect positively on the trust and competence that IWTSD has earned throughout the Department of Defense, its international partners, and other federal organizations to rapidly conduct critical RDT&E and provide innovative products to fill their capability gaps.$$, NULL, 75411000, 76559000, 78761000, NULL, NULL, 37, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 194610000, 288428000, 73618000, 73618000, NULL, 73618000, 80354000, $$The U.S. Department of War (DoW) has launched the Secretariat for Special Operations (SSO) to modernize the oversight and administration of U.S. Special Operations Command and the department’s irregular warfare (IW) capabilities. Directed by Congress, this initiative aims to address evolving global security challenges while preserving decades of operational legacy. A key component of this effort is the transformation of the Irregular Warfare Technical Support Directorate (IWTSD) into the newly named Capability Development and Innovation (CD&I) directorate during FY 2025. While the transition maintains the organization's longstanding commitment to rapid research and development (R&D) solutions and innovation, it incorporates structural updates for enhanced agility and focus across four specialized divisions: Operational Demands and Threat Analysis (ODTA), Irregular Warfare Capability Development (IWCD), Assessment of Prototypes and Experimentation (APEX), and Global Innovation Partnerships (GIP). These divisions bring streamlined processes to threat analysis, capability development, prototype testing, and international collaboration, underscoring a holistic approach to irregular warfare. CD&I maintains the IWTSD’s structure to rapidly fill capability gaps, to include sensitive activity support, force protection and subterranean activities, lethality, information dominance, counter-unmanned systems and unmanned systems, and personnel protection and human optimization. Though this strategic restructuring reflects an intentional modernization effort, it remains a work in progress, with ongoing adjustments to align emerging priorities, refine operational frameworks, and address the ever-changing landscape of global security needs. During FY 2026 and into FY 2027, CD&I will continue to focus its R&D activities to rapidly fill the immediate, emerging, and critical capability gaps for those at the tactical edge to include our nation’s special operations forces, other military operators, intelligence analysts, and first responders. The number of capability gaps CD&I can address are reduced due to the increased cost of incorporating artificial intelligence, machine learning, cyber hardening, and DoW safety testing of prototype systems prior to operational test and evaluation (OT&E). For instance, the focus on increased lethality has driven up costs to meet DoW safety and testing requirements. With the change from IWTSD to CD&I and starting in FY27, projects will be distributed between two divisions: • Irregular Warfare Capability Development (IWCD) • Assessment, Prototyping, and Experimentation (APEX) Each of the 11 legacy IWTSD subgroups have enduring R&D partnerships with USSOCOM and its components, the Services, and many DoW agencies. During FY 2025, IWTSD partnered with USSOCOM, the Services, and DoW agencies to transition or commit to transition over 28 products to a Program of Record and provided over 42 prototypes to users for OT&E. IWTSD’s International R&D program has helped other DoW Components and organizations initiate task plans, which support execution of over about $70 million dollars to rapidly develop and prototype new technology and innovation through collaboration and cost sharing with Israel. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                     Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:              PE 0603122D8Z / Combating Terrorism Technology Support Advanced Technology Development (ATD) While supporting the National Defense Strategy (NDS) by filling capability gaps to address our adversaries, the CD&I program will continue to identify capabilities to combat terrorism and irregular adversaries, and quickly deliver these capabilities to U.S. DoW, interagency, and international partners through rapid research and development, advanced studies, and technical innovation. CD&I is unique in its approach, annually obtaining joint requirements directly from major Commands, Services, military operators, intelligence analysts, and first responders, and discussing those requirements with industry before the requirements are released in Broad Agency Announcements (BAA). The CD&I program, justified in the R-2 exhibit, identifies the projects that are fully or partially funded by Congressional appropriations for the CD&I program. However, CD&I also develops technology and provides support using external funds provided by other DoW, federal departments and international partnerships. These external funds are not reflected in this R-2 justification. However, the number of activities does reflect positively on the trust and competence that CD&I has earned throughout the Department of War, its international partners, and other federal organizations to rapidly conduct critical RDT&E and provide innovative products to fill their capability gaps.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603133D8Z$$, $$Foreign Comparative Testing$$, $$rdte_dw_ba3$$, $$dw_socom$$, 2026, 27958000, 26578000, 30007000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 68, "original_pe": "0603133D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department of Defense (DoD) initiatives to Defend the Homeland, Deter Strategic and Regional Aggression, and Build a Resilient Joint Force and Defense Ecosystem. The FCT program supports the Department's initiatives by testing mature equipment, munitions, and technologies of U.S. allies and partners to determine the ability of such to satisfy U.S. military requirements or to correct operational deficiencies. By leveraging the Research & Development (R&D) investments of international allies and partners, FCT avoids the additional financial cost and time of redundant research and engineering activities. FCT procures technologies and prototypes produced by allied and partner nations, and formally evaluates them against the capability requirements of the Services and Agencies, thereby determining their suitability to deliver capability and counter emerging threats. The results of comparing test results against requirements informs, and often accelerates, the Services’ and Agencies’ acquisition decisions. Additionally, participation in the FCT program conveys the legal authority (Title 10, U.S. Code, Section 2350a(g)) for the Service or Agency to move immediately to procurement where appropriate, which further speeds the DoD acquisition process. FCT strengthens alliances by promoting technologies that increase military interoperability, as well as serving as a catalyst for teaming between the militaries and business sectors of the U.S. and each participating partner nation. Many FCT projects have resulted in the licensed production of a qualified foreign item in the United States, in addition to creating jobs and contributing to local economies. To date, companies from 34 states have benefited from FCT projects. International Collaboration and International Experimentation, initiated in FY2025 as an expansion of the FCT program, extends the evaluation of innovative foreign capabilities into operationally relevant environments. The focus and intent of these cooperative/collaborative efforts is to develop flexible deterrent options that prioritize interoperability while increasing resiliency in the defense ecosystem by working even more closely with our network of allies and partners around the globe. The FCT Program’s broad reach across our allies and friendly foreign countries enables development of innovative, cost effective, and interoperable solutions to meet the needs communicated by the Joint Chiefs of Staff and the Combatant Commanders. Measurable Outcomes: Over its 44-year history, FCT has a transition rate of 52 percent (403 out of 778) for completed projects. Of the 403 projects that tested successful, 310 or 77 percent resulted in follow-on procurements of over $14.124 billion. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                  Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:            PE 0603133D8Z / Foreign Comparative Testing Advanced Technology Development (ATD) In FY26, FCT organized sub-projects by focus areas aligned to specific, persistent capability gaps. Aligning investments by focus areas allows Prototyping and Experimentation (P&E) to rapidly respond to urgent and emergent requirements at the speed of relevance. Focus areas include: - Kill Web Interoperability: The processes by which Joint Force Commanders plan, direct, coordinate, and control forces to accomplish assigned missions and enable Joint kill webs. - Resilient Communications: The ability to maintain hardened mission-capable systems that allow for secure freedom of communications in contested electromagnetic spectrum environments. This includes alternate position, navigation, and timing. - Sensors and Data Analytics: Networks of sensors and data collection assets, data analysis, and dissemination resources used to provide information to the Joint force about strategic and tactical threats. - Collaborative Multi-Domain Autonomy: The use of multi-domain uncrewed systems and autonomy to increase warfighting capabilities and to mitigate/negate risk to warfighters. - Contested Logistics / Sustainment: The coordinated use, synchronization, and often sharing of logistics resources to deploy, support, and sustain highly dispersed Joint forces in highly contested environments. This also includes other sustainment areas such as supply chain reduction efforts; additive manufacturing; operational/tactical water purification; and sustainment and transportation innovations. - Weapons Kinetic/Non-Kinetic Effects: The delivery of weapon systems and long-range kinetic and non-kinetic effects in support of Joint offensive and defensive tasks to create specific lethal effects on a target. This area includes counter position, navigation, and timing; and techniques designed to deceive enemy observers and/or mitigate, disrupt, or negate adversary capabilities. Emerging Prototypes and Enablers: Supports the acceleration of DoD, CCMD, and Service priority efforts which provide unique capability and/or address critical gaps. This focus area incorporates Combat Support/Combat Enablers; Special Forces Capabilities; Medical Technologies/Devices; Special Access Program assimilation and operational management; prototyping through small business and non-traditional pathways; and the rapid development of technologies for inclusion in experimentation venues. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:              PE 0603133D8Z / Foreign Comparative Testing Advanced Technology Development (ATD)$$, NULL, 25798000, 26035000, 27496000, NULL, NULL, 38, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 29464000, 27662000, 24950000, 24950000, NULL, 24950000, 27500000, $$This program supports the Department of War (DoW) initiatives to Defend the Homeland, Deter Strategic and Regional Aggression, rebuild the Joint Force and rebuild a resilient defense ecosystem. The Foreign Comparative Testing (FCT) program supports the department's initiatives by testing mature equipment, munitions, and technologies of U.S. allies and partners. The program verifies the performance and validates the ability of foreign products to; satisfy U.S. military requirements, correct operational deficiencies, or meet other U.S. requirements. By leveraging the Research & Development (R&D) investments of international allies and partners, FCT program enables U.S. RDT&E funding to be applied to critical technology areas avoiding duplicative R&D efforts and accelerates delivery of capability to the warfighter. The results of the programs testing informs and accelerates the Services and Agencies acquisition decisions. Additionally, participation in the FCT program conveys the legal authority (Title 10, U.S. Code, Section 2350a(g)) for the Service or Agency to move immediately to procurement where appropriate, which further accelerates the DoW acquisition process. The FCT Program’s broad reach across our allies and friendly foreign countries enables the acquisition of innovative, cost effective, and interoperable solutions to meet the needs communicated by the Military Services, US Special Operations Command (USSOCOM), Joint Chiefs of Staff and Combatant Commanders, and other US Government Agencies. FCT strengthens alliances by evaluating technologies that increase military interoperability with our allies. The program serves as a catalyst for teaming between the militaries and business sectors of the U.S. and each participating partner nation. To date, companies from 35 states have benefited from FCT projects by partnering for licensed production of a qualified foreign item in the United States creating jobs, contributing to local economies, and strengthening the U.S. defense production base. Measurable Outcomes: Over its 47-year history, FCT has a transition rate of 60 percent (535 out of 891) for completed projects. Of the 535 projects that tested successful, 384 or 71.8 percent resulted in follow-on procurements of over $15 billion. The remaining 151 updated Military Specifications, Military Standards, Requirements Documents for Programs of Record (POR), and for future/developmental acquisition efforts. In FY 2026, FCT organized sub-projects by focus areas aligned to specific, persistent capability gaps. Aligning investments by focus areas allows Prototyping and Experimentation (P&E) to rapidly respond to urgent and emergent requirements at the speed of relevance. Focus areas include: Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                  Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:          PE 0603133D8Z / Foreign Comparative Testing Advanced Technology Development (ATD) - Kill Web Interoperability: The processes by which Joint Force Commanders plan, direct, coordinate, and control forces to accomplish assigned missions and enable Joint Kill webs. - Resilient Communications: The ability to maintain hardened mission-capable systems that allow for secure freedom of communications in contested electromagnetic spectrum environments. This includes alternate position, navigation, and timing. - Sensors and Data Analytics: Networks of sensors and data collection assets, data analysis, and dissemination resources used to provide information to the Joint Force about strategic and tactical threats. - Collaborative Multi-Domain Autonomy: The use of multi-domain uncrewed systems and autonomy to increase warfighting capabilities and to mitigate/negate risk to warfighters. - Contested Logistics / Sustainment: The coordinated use, synchronization, and often sharing of logistics resources to deploy, support, and sustain highly dispersed Joint Forces in highly contested environments. This also includes other sustainment areas such as supply chain reduction efforts; additive manufacturing; operational/tactical water purification; and sustainment and transportation innovations. - Weapons Kinetic/Non-Kinetic Effects: The delivery of weapon systems and long-range kinetic and non-kinetic effects in support of Joint offensive and defensive tasks to create specific lethal effects on a target. This area includes counter position, navigation, and timing; and techniques designed to deceive enemy observers and/or mitigate, disrupt, or negate adversary capabilities. - Emerging Prototypes and Enablers: Supports the acceleration of DoW, Combatant Command (CCMD), and Service priority efforts which provide unique capability and/or address critical gaps. This focus area incorporates Combat Support/Combat Enablers; Special Forces Capabilities; Medical Technologies/Devices; Special Access Program assimilation and operational management; prototyping through small business and non-traditional pathways; and the rapid development of technologies for inclusion in experimentation venues. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:         PE 0603133D8Z / Foreign Comparative Testing Advanced Technology Development (ATD)$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603225D8Z$$, $$Joint DoD-DoE Munitions Technology Development$$, $$rdte_dw_ba3$$, $$dw$$, 2026, 35505000, 18553000, 19826000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 68, "original_pe": "0603225D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department's initiatives to Reestablish Deterrence, Prevail in Conflict, Defend the Homeland, and Build Sustainable and Long-Term Advantages. The mission of the Joint DoD/DOE Munitions Technology Development Program (JMP) is to develop new and innovative science and technology (S&T) to enable significant advancements in the state-of-the-art for conventional munitions. The JMP portfolio comprises essential, cross-cutting, and foundational S&T investments that enable future force operational capabilities in the near, mid, and far term. Additionally, JMP’s efforts form the foundation of DoD munitions research design, testing, and manufacturing. A memorandum of understanding between the Department of Defense and the Department of Energy provides the basis for the cooperative effort and for cost sharing the mutually beneficial technology munitions advancements. The funding budgeted by the DoD to this program are matched, at a minimum, dollar for dollar by the DOE. Through this interdepartmental cooperation, the DoD leverages DOE’s substantial investments in intellectual capital, highly specialized skills, advanced scientific equipment and facilities, and computational tools not available within the DoD. This includes developing computational tools, which leverage AI technologies to aid munitions designers in developing novel high entropy alloys, advanced energetics, and fast running damage models for improved assessment of maritime lethality. These advancements through JMP provide foundational capabilities that impact a wide range of munitions including One-Way Attack, counter-small UAS technologies, and munitions that may be utilized for Homeland Missile Defense. The integration of DOE technologies with DoD Joint Services’ needs has provided major advances in munition capabilities over many years and continues to play a crucial role in the exploration, development, and transition of new technologies needed by the services. The JMP has established a successful collaborative munitions community of DoD and DOE scientists and engineers that develop technologies of interest to both Departments. A structured cadence of threat informed requirements development, Joint Service informed portfolio development, and bi-annual technical reviews ensure that the JMP’s investments address high-priority DoD gaps, needs, and challenges. The JMP portfolio is organized into four Technology Coordination Groups (TCG), led by DoD Service laboratory subject matter experts, which evaluate each project’s technical progress and continued relevance to the mission. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:         PE 0603225D8Z / Joint DoD-DoE Munitions Technology Development Advanced Technology Development (ATD)$$, NULL, 52914000, 63823000, 68457000, NULL, NULL, 45, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 19201000, 33592000, 45375000, 45375000, NULL, 45375000, 70126000, $$This program supports the Department's initiatives to Reestablish Deterrence, Prevail in Conflict, Defend the Homeland, and Build Sustainable and Long-Term Advantages. The mission of the Joint DoW/DOE Munitions Technology Development Program (JMP) is to develop new and innovative science and technology (S&T) to enable significant advancements in the state-of-the-art for conventional munitions. The JMP portfolio comprises essential, cross-cutting, and foundational S&T investments that enable future force operational capabilities in the near, mid, and far term. Additionally, JMP’s efforts form the foundation of Department of War (DoW) munitions research design, testing, and manufacturing. A memorandum of understanding signed in 1985 between the Department of War (DoW) and the Department of Energy provides the basis for the cooperative effort and for cost sharing the mutually beneficial technology munitions advancements. The funding budgeted by the DoW to the primary JMP effort within this program are matched, at a minimum, dollar for dollar by the DOE. Through this interdepartmental cooperation, the DoW leverages DOE’s substantial investments in intellectual capital, highly specialized skills, advanced scientific equipment and facilities, and computational tools not available within the DoW. This includes developing computational tools, which leverage AI technologies to aid munitions designers in developing novel high entropy alloys, advanced energetics, and fast running damage models for improved assessment of maritime lethality. These advancements through JMP provide foundational capabilities that impact a wide range of munitions including One-Way Attack, counter-small Unmanned Aerial System (UAS) technologies, and munitions that may be utilized for Homeland Missile Defense. The integration of DOE technologies with DoW Joint Services’ needs has provided major advances in munition capabilities over many years and continues to play a crucial role in the exploration, development, and transition of new technologies needed by the services. The JMP has established a successful collaborative munitions community of DoW and DOE scientists and engineers that develop technologies of interest to both Departments. A structured cadence of threat informed requirements development, Joint Service informed portfolio development, and bi-annual technical reviews ensure that the JMP’s investments address high-priority DoW gaps, needs, and challenges. The JMP portfolio is organized into four Technology Coordination Groups (TCG), led by DoW Service laboratory subject matter experts, which evaluate each project’s technical progress and continued relevance to the mission. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:         PE 0603225D8Z / Joint DoD-DoE Munitions Technology Development Advanced Technology Development (ATD)$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603288D8Z$$, $$Science and Technology (S&T) Analytic Assessments$$, $$rdte_dw_ba3$$, $$dw_ousd_re$$, 2026, 41010000, 31096000, 27897000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 68, "original_pe": "0603288D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This PE supports the Department's initiatives to Revive the Warrior Ethos, Rebuild Our Military, and Reestablish Deterrence. This program directly supports the Office of Strategic Intelligence and Analysis (OSI&A) for the Office of the Under Secretary of Defense, Research and Engineering (OUSD(R&E)). OSI&A’s campaign of analysis approach integrates intelligence reporting and independent technical expertise to execute comparative assessments. These assessments inform investment decisions and shape the development of innovative capabilities to address emerging threats and opportunities from a diverse range of state and non-state actors as outlined in the Interim National Defense Strategy Guidance (INDSG) and as reported through the Intelligence Community (IC). The complexity of capability gaps in the future operating environment combined with the speed of emerging threat development requires a broadly scoped “red vs blue” approach. This approach provides integrated baselines for OUSD(R&E) analyses and investment decisions that are reflective of cross-cutting Joint Force plans, missions, and concepts. Trends and potential impacts related to global critical and emerging technology developments are analyzed and assessed, and findings are integrated with IC reporting to enable decision advantage in OUSD(R&E) and inform strategies for maintaining technological superiority and modernizing key capabilities for the Joint Force. Analysis and assessments are focused on challenges related to INDSG objectives and competitors' research and development trends. Two lines of effort accomplish this mission: 1) Science and Technology (S&T) Analytic Assessments integrate information from the acquisition, intelligence, operational, and S&T communities to quantify key attributes of emerging critical challenges and assess counter technology opportunities. The framework includes execution of the following activities: - Net Technical Assessments (NTA). OSI&A partners with Federally Funded Research and Development Centers, University Affiliated Research Centers, industry, and academia to conduct comparative assessments of critical technologies to determine technological advantage and inform investment decisions across the Department of Defense (DoD) S&T Enterprise. Critical technologies of interest to the DoD and strategic context drawn from the NDS, NDSTS, and DoD planning efforts set the bounds for the assessment of technological applications that could deliver operational advantage to the Joint Force along future development and deployment timelines. - Operational and Technical Assessments. Evaluations of DoD operational scenarios and warfighting concepts that identify operational gaps, incorporating IC-derived adversary threat trends and the technical demands of the future operational environment to determine challenges that could be mitigated or eliminated through the application of emerging and disruptive technologies. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                    Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:             PE 0603288D8Z / Science and Technology (S&T) Analytic Assessments Advanced Technology Development (ATD) - Technology-based Wargames. Execution of an array of purpose-built games and workshops that integrate the operational, technology, and intelligence communities to characterize emerging technologies in the context of the future operational environment, evaluate their disruptive potential, and identify opportunities and challenges. Insights from these efforts inform programmatic and policy decisions related to the development of operational concepts across the Department. 2) Technology Watch and Horizon Scanning combines analysis of complex, unstructured, open-source data sets with intelligence reporting to enable monitoring and analysis of global research and development activities, underpinning characterization of the global technology environment and informing portfolio investment decisions across the DoD S&T Enterprise. These characterizations enable Global Research Watch activities and establish the global technology landscape that informs OSI&A S&T analytic assessment efforts and frames the larger campaign of analysis. The framework includes the following activities: - Technology Watch. Analysis of global open-source science, technology, research, and development efforts and in-person conference, symposium, and workshop attendance to characterize the global landscape of known science, technology, and concepts and to identify trends that can provide indicators and warnings of disruptive technology advances. Integrating the methodologies and findings from technology forecasting, maturation assessments, and NTA efforts to identify technological development areas for research and investment. - Horizon Scanning. Systematic execution of analytic techniques applied to large, complex open-source data for the identification of emerging science and technology capable of altering the future operating environment. - Intelligence Integration. Structured execution of recurring technical exchanges between the OUSD(R&E) stakeholders and S&T intelligence subject matter experts. These engagements enable the direct exchange of OUSD(R&E) intelligence needs and IC finished intelligence products to complement open-source findings and establish a comprehensive understanding of the global technology landscape. Additionally, OUSD(R&E) level input and perspectives support IC scientific and technical intelligence initiatives and inform intelligence community priorities, investment decisions, and strategic direction. - International Partner Collaboration. Cooperative identification and early-stage investigation of emerging technologies that generate opportunities and solve critical challenges common to the national security of the U.S. and our international partners. Due to the emergent nature of challenges and threats, specific analytic foci are unlikely to be identified beyond the current budget year. The process for developing and executing assessments can span fiscal years and may have multiple phases as trends progress and new information arises through open-source technology trend analysis and intelligence reporting. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:           PE 0603288D8Z / Science and Technology (S&T) Analytic Assessments Advanced Technology Development (ATD)$$, NULL, 46882000, 52305000, 57984000, NULL, NULL, 48, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 26886000, 41254000, 36917000, 36917000, NULL, 36917000, 62983000, $$This program element supports the Department's initiatives to Revive the Warrior Ethos, Rebuild Our Military, and Reestablish Deterrence. This program directly supports the Joint Assured Technical Overmatch Center (JATOC) - renamed from the Office of Strategic Intelligence and Analysis (OSI&A) in FY 2026 - for the Office of the Under Secretary of War for Research and Engineering (OUSW(R&E)). JATOC’s campaign of analysis integrates intelligence reporting and independent technical expertise to execute comparative assessments and will be increasingly supported by the curation of data and application of artificial intelligence (AI) tools. These assessments rapidly inform investment decisions and shape the development of innovative capabilities to address emerging threats from a diverse range of state and non-state actors as outlined in the National Defense Strategy (NDS) and as reported through the Intelligence Community (IC). The complexity of identifying capability gaps in the future operating environment—combined with the speed of emerging threat and global commercial development—requires a broadly- scoped approach. This approach provides integrated baselines for OUSW(R&E) analyses and investment decisions that reflect cross-cutting Joint Force plans, missions, and concepts. Trends and potential impacts related to global critical and emerging technology developments are analyzed and integrated with IC reporting to identify potential gaps and assess opportunities to fill those gaps, enabling decision advantage in OUSW(R&E) and informing strategies for maintaining technological superiority and modernizing key capabilities for the Joint Force. Analyses and assessments are focused on challenges related to NDS objectives and competitors' research and development trends. Two lines of effort accomplish this mission: 1) Assured Technical Overmatch (ATO). This project integrates information from the acquisition, intelligence, operational, and scientific and technical (S&T) communities to quantify key attributes of emerging critical challenges and assess counter technology opportunities. The framework includes execution of the following activities: - Technology Overmatch. JATOC partners OUSW(R&E) subject matter experts with Federally Funded Research and Development Centers and University Affiliated Research Centers to identify potential future military capability gaps and propose technological solutions for OUSW(R&E) and broader Department consideration. These efforts are conducted in overlapping six-month sprints and are informed by intelligence reporting, operational plans, service requirements, and Department-funded R&D as well as commercial and academic research activities. Results are consolidated in a graphical overview of the problem and potential solutions, along with white papers outlining details for proposed solutions to help assure technology overmatch. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                   Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:             PE 0603288D8Z / Science and Technology (S&T) Analytic Assessments Advanced Technology Development (ATD) - Competitive Landscape Assessments (CLA). JATOC partners with Federally Funded Research and Development Centers, University Affiliated Research Centers, industry, and academia to conduct comparative assessments of critical technologies to determine technological advantage and inform investment decisions across the Department of War (DoW) S&T Enterprise. Critical technologies of interest to the DoW and strategic context drawn from the NDS, National Defense Science and Technology Strategy (NDSTS), and other DoW planning efforts set the bounds for the assessment of technological applications that could deliver operational advantage to the Joint Force along future development and deployment timelines. - Operational and Technical Assessments. Evaluations of DoW operational scenarios and warfighting concepts that identify operational gaps, incorporating IC-derived adversary threat trends and the technical demands of the future operational environment to determine challenges that could be mitigated or eliminated through the application of emerging and disruptive technologies. - Technology-based Wargames. Execution of an array of purpose-built games and workshops that integrate the operational, technology, and intelligence communities to characterize emerging technologies in the context of the future operational environment, evaluate their disruptive potential, and identify opportunities and challenges. Insights from these efforts inform programmatic and policy decisions related to the development of operational concepts across the Department. 2) Global Research Watch (GRW). This project combines analyses of complex, unstructured, open-source data sets with intelligence reporting to enable monitoring and analyses of global research and development activities, underpinning characterization of the global technology environment and informing portfolio investment decisions across the DoW S&T Enterprise. These characterizations enable GRW activities and establish the global technology landscape that informs JATOC S&T analytic assessment efforts and frames the larger campaign of analysis. The framework includes the following activities: - Technology Watch. Analysis of global open-source science, technology, research, and development efforts and in-person conference, symposium, and workshop attendance to characterize the global landscape of known science, technology, and concepts and to identify trends that can provide indicators and warnings of disruptive technology advances. Integrating the methodologies and findings from technology forecasting, maturation assessments, and CLA efforts to identify technological development areas for research and investment. - Horizon Scanning. Systematic execution of analytic techniques applied to large, complex open-source data for the identification of emerging science and technology capable of altering the future operating environment. - Intelligence Integration. Structured execution of recurring technical exchanges between OUSW(R&E) stakeholders and S&T intelligence subject matter experts. These engagements enable the direct exchange of OUSW(R&E) intelligence needs and IC finished intelligence products to complement open-source findings and establish a comprehensive understanding of the global technology landscape. Additionally, OUSW(R&E) input and perspectives support IC S&T intelligence initiatives and inform IC priorities, investment decisions, and strategic direction. - International Partner Collaboration. Cooperative identification and early-stage investigation of emerging technologies that generate opportunities and solve critical challenges common to the national security of the U.S. and our international partners. Due to the emergent nature of challenges and threats, specific analytic foci are unlikely to be identified beyond the current budget year. The process for developing and executing assessments can span fiscal years and may have multiple phases as trends progress and new information arises through open-source technology trend analysis and intelligence reporting. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                      Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:       PE 0603288D8Z / Science and Technology (S&T) Analytic Assessments Advanced Technology Development (ATD)$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L039$$, $$Reactor Components$$, $$proc_navy_1810_ba1$$, $$navsea$$, 2026, 3313000, 0, 0, NULL, $${"page": 96, "ba_num": "01", "source": "p1_fy26", "ba_name": "Ships support equipment", "line_no": "39", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "01", "appr": "OPN", "title": "P-1 Line 36", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 135802, "p1_line_num": 36, "fy27_total_K": 135802}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"note": "no_parser_pair", "source": "p40_fy26_v179"}, "fy26_v197": {"method": "title_fuzzy_partial", "delta_K": 3313, "src_pdf": "Budget J-Books/FY27/Navy/OPN_BA1_Book.pdf", "mapped_K": 5108087, "applied_at": "2026-05-09T_v197d", "table2_total_K": 5802107, "supersedes_partial": "fy26_v179_concentrated", "unmapped_residual_K": 694020}, "fy26t_qty": null, "fy26d_cost": 0, "fy26r_cost": 3313000, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 445974000, 474806000, 135802000, 135802000, 0, 135802000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA1_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603289D8Z$$, $$Advanced Innovative Analysis and Concepts$$, $$rdte_dw_ba3$$, $$dw_strato$$, 2026, 57457000, 63895000, 56390000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 68, "original_pe": "0603289D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department's initiatives to Deter Aggression and Prevail in Conflict, Defend the Homeland, Build Sustainable and Long-Term Advantage, and Build a Resilient Joint Force and Defense Ecosystem. The Strategic Capabilities Office (SCO) conducts analysis to identify and accelerate the development, demonstration, and transition of operationally impactful capabilities to shape and counter emerging threats and increase the lethality of the Joint Force in contested environments. In a partnership endeavor across the Office of the Secretary of Defense (OSD), Joint Staff, Combatant Commands (CCMDs), the Services, the Intelligence Community (IC), and other U.S. Government agencies, the SCO combines capability innovation with new concepts for warfighting that leverage new technology areas, including autonomy, artificial intelligence, and machine learning. SCO conducts projects on accelerated timelines, in all warfighting domains, at any classification or access level. The Advanced Innovative Analysis and Concepts program supports development, study, and analysis of integrated concepts and prototypes, analysis in support of ongoing efforts to shape and counter emerging threats, cross-Service and cross-Defense/Intelligence concepts, and red-teaming. Projects focus on proving component and subsystem maturity prior to integration in major systems, and may involve risk reduction initiatives. This program also supports the development of concept proposals for assessment by the Technical and Transition Cross Functional Teams established in accordance with the National Defense Authorization Act (NDAA) for FY 2020 for development under the Advanced Innovative Technologies Program Element. Due to the nature of these projects, specific applications and detailed plans are available at a higher classification level. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                 Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:          PE 0603289D8Z / Advanced Innovative Analysis and Concepts Advanced Technology Development (ATD)$$, NULL, 53184000, 54233000, 55410000, NULL, NULL, 49, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 54976000, 56677000, 51960000, 51960000, NULL, 51960000, 55426000, $$This program supports the Department's initiatives to Deter Aggression and Prevail in Conflict, Defend the Homeland, Build Sustainable and Long-Term Advantage, and Build a Resilient Joint Force and Defense Ecosystem. The Strategic Capabilities Office (SCO) conducts analysis to identify and accelerate the development, demonstration, and transition of operationally impactful capabilities to shape and counter emerging threats and increase the lethality of the Joint Force in contested environments. In a partnership endeavor across the Office of the Secretary of War (OSW), Joint Staff, Combatant Commands (CCMDs), the Services, the Intelligence Community (IC), and other U.S. Government agencies, the SCO combines capability innovation with new concepts for warfighting that leverage new technology areas, including autonomy, artificial intelligence, and machine learning. SCO conducts projects on accelerated timelines, in all warfighting domains, at any classification or access level. The Advanced Innovative Analysis and Concepts program supports development, study, and analysis of integrated concepts and prototypes, analysis in support of ongoing efforts to shape and counter emerging threats, cross-Service and cross-Defense/Intelligence concepts, and red-teaming. Projects focus on proving component and subsystem maturity prior to integration in major systems, and may involve risk reduction initiatives. This program also supports the development of concept proposals for assessment by the Technical and Transition Cross Functional Teams established in accordance with the National Defense Authorization Act (NDAA) for FY 2020 for development under the Advanced Innovative Technologies Program Element. Due to the nature of these projects, specific applications and detailed plans are available at a higher classification level. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:         PE 0603289D8Z / Advanced Innovative Analysis and Concepts Advanced Technology Development (ATD)$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603781D8Z$$, $$Software Engineering Institute (SEI)$$, $$rdte_dw_ba3$$, $$dw$$, 2026, 12972000, 15747000, 16982000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 70, "original_pe": "0603781D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Departments initiatives to Build a Sustainable and Long-Term Advantage, and Build a Resilient Joint Force and Defense Ecosystem. Software is more pervasive than ever, and computer programs are growing in size and complexity. Designing, managing, and securing integrated, complex, and large- scale mission-critical systems are abilities that the Department of Defense (DoD) and the Defense Industrial Base (DIB) have not yet mastered. Reliance on software- intensive mobile and net-based products and systems has increased (e.g., Joint Tactical Radio System, USS ZUMWALT (DDG-1000), Joint Strike Fighter, F-22, and Army Modernization). As stated in the February 2018 Defense Science Board Report, “Design and Acquisition of Software for Defense Systems,” software is a crucial and growing part of weapons systems and the national security mission, and the DoD must address its ability to build and sustain software continuously and indefinitely. With growing global parity in software engineering, the DoD must maintain leadership to ensure a competitive advantage. The Carnegie-Mellon University Software Engineering Institute (SEI) Federally Funded Research and Development Center (FFRDC) was established in 1984 as an integral part of the DoD’s initiative to identify, evaluate, and transition software engineering technologies and practices. The mission of the SEI is to provide the DoD with technical leadership and innovation through research and development to advance the practice of software engineering and technology. The SEI works across government, industry, and academia to improve the state of software engineering from the technical, acquisition, and management perspectives. The SEI engages in research and development of critical software technologies and tools and collaborates with the larger software engineering research community. It facilitates rapid transition of software engineering technologies into practice and evaluates emerging software engineering technologies to determine their potential for improving software-intensive DoD systems. Since its inception, the SEI has helped to transform the fields of software engineering and acquisition, network security, real-time systems, software architectures, and software-engineering process management. The SEI Program Element (PE) addresses the critical need to research, develop, and rapidly transition state-of-the-art software technology, tools, development environments, and best practices to improve the engineering, management, fielding, evolution, acquisition, and sustainment of software-intensive DoD systems. The Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                           Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:            PE 0603781D8Z / Software Engineering Institute (SEI) Advanced Technology Development (ATD) research conducted by this PE directly benefits the technical domains, such as Command, Control, Communications, Computers, and Intelligence (C4I), Autonomy and Artificial Intelligence (AI), Cyber, and Engineered Resilient Systems.$$, NULL, 10183000, 10167000, 10154000, NULL, NULL, 72, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 16360000, 12789000, 10227000, 10227000, NULL, 10227000, 10120000, $$This program supports the Departments initiatives to Build a Sustainable and Long-Term Advantage, and Build a Resilient Joint Force and Defense Ecosystem. Software is more pervasive than ever, and computer programs are growing in size and complexity. Designing, managing, and securing integrated, complex, and large- scale mission-critical systems are abilities that the Department of War (DoW) and the Defense Industrial Base (DIB) have not yet mastered. Reliance on software- intensive mobile and net-based products and systems has increased (e.g., Joint Tactical Radio System, USS ZUMWALT (DDG-1000), Joint Strike Fighter, F-22, and Army Modernization). As stated in the February 2018 Defense Science Board Report, “Design and Acquisition of Software for Defense Systems,” software is a crucial and growing part of weapons systems and the national security mission, and the DoW must address its ability to build and sustain software continuously and indefinitely. With growing global parity in software engineering, the DoW must maintain leadership to ensure a competitive advantage. The Carnegie-Mellon University Software Engineering Institute (SEI) Federally Funded Research and Development Center (FFRDC) was established in 1984 as an integral part of the DoW’s initiative to identify, evaluate, and transition software engineering technologies and practices. The mission of the SEI is to provide the DoW with technical leadership and innovation through research and development to advance the practice of software engineering and technology. The SEI works across government, industry, and academia to improve the state of software engineering from the technical, acquisition, and management perspectives. The SEI engages in research and development of critical software technologies and tools and collaborates with the larger software engineering research community. It facilitates rapid transition of software engineering technologies into practice and evaluates emerging software engineering technologies to determine their potential for improving software-intensive DoW systems. Since its inception, the SEI has helped to transform the fields of software engineering and acquisition, network security, real-time systems, software architectures, and software-engineering process management. The SEI program addresses the critical need to research, develop, and rapidly transition state-of-the-art software technology, tools, development environments, and best practices to improve the engineering, management, fielding, evolution, acquisition, and sustainment of software-intensive DoW systems. The research conducted by this Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                               Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:        PE 0603781D8Z / Software Engineering Institute (SEI) Advanced Technology Development (ATD) PE directly benefits the technical domains, such as Command, Control, Communications, Computers, and Intelligence (C4I), Autonomy and Artificial Intelligence (AI), Cyber, and Engineered Resilient Systems.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305245D8Z$$, $$Intelligence Capabilities and Innovation Investments$$, $$rdte_dw_ba4$$, $$dw_classified$$, 2026, 43596000, 60994000, 51784000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 73, "original_pe": "0305245D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$Classified program.$$, NULL, 16212000, 20780000, 21236000, NULL, NULL, 136, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 51784000, 43596000, 15047000, 15047000, NULL, 15047000, 21662000, $$Classified program.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603161D8Z$$, $$Nuclear Matters, Advanced Component Development & Prototypes$$, $$rdte_dw_ba4$$, $$dw$$, 2026, 55465000, 57535000, 63162000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 70, "original_pe": "0603161D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This Program Element supports the Interim National Defense Strategic Guidance (INDSG) counter the growing multi-domain threat posed by China; Deterring strategic attacks against the United States, Allies, and partners; Deterring aggression, while being prepared to prevail in conflict when necessary – prioritizing the challenge of China in the Indo-Pacific region, then the Russia challenge in Europe, and; Building a resilient Joint Force and defense ecosystem. Nuclear Matters, Advanced Component Development & Prototypes addresses the need to defend and deter against weapons of mass destruction threats and to safeguard personnel, prevent unauthorized access to equipment, installations, material, and documents, and to safeguard the foregoing against espionage, sabotage, damage, and theft. This program oversees advanced engineering development and rapid fielding throughout the Department of Defense (DoD) for an integrated and systemic approach to develop material solutions. The Physical Security Enterprise and Analysis Program (PSEAP) avoids duplication of effort, ensures systems integration, and promotes interoperability and sustainability. The material solutions either (a) lead to a Program of Record, (b) become technology insertions into existing programs; or (c) advance to being a certified Commercial/Government off-the-shelf product. The PSEAP advances enterprise-level physical security RDT&E solutions to reduce risk created by current and emerging threat by analyzing, researching, developing, demonstrating, and evaluating interoperable solutions to transition capability to warfighters. Collaboration with DoD Components, other government agencies, and the international community to prioritize and close capability gaps is a top priority of the PSEAP and the physical security community. National Technical Nuclear Forensics (NTNF) mission requirements and responsibilities derive from multiple source documents. Per National Security Presidential Memorandum 35 (NSPM 35), the DoD leads the United States (U.S.) Government (USG) post-detonation NTNF capability. NSPM 35 also directs that the US will maintain and advance a robust NTNF capability to detect, identify, locate, and characterize the attribution of the source of an actual or attempted nuclear or radiological attack in all environments, to include underground, underwater, in the atmosphere, and space. Per DoD Directive S-2060.04, the Office of the Undersecretary of Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                   Date: June 2025 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:                PE 0603161D8Z / Nuclear Matters, Advanced Component Development & Prototypes Advanced Component Development & Prototypes (ACD&P) Defense for Acquisition & Sustainment (OUSD(A&S)) is the office responsible for developing and leading the DoD’s NTNF capabilities. Per the 2022 Nuclear Posture Review (NPR) Direction, greater investment in NTNF tools is required to ensure they remain responsive to the threat, and thus scientifically credible and internationally accepted to hold states facilitating acts of nuclear terrorism accountable. The FY 2022 – FY2026 Nuclear Forensics and Attribution Strategic (NFAS) Plan requires an NTNF capability to collect, analyze, and evaluate both air and ground post-nuclear detonation samples at accelerated directed timelines. The DoD mission to collect, analyze, and evaluate post-detonation prompt signals and nuclear debris is critical to our national defense and security to ensuring the USG can identify the source of nuclear material and hold those involved or supporting an attack accountable. Internal and independent assessments indicate that new capabilities are needed to sustain an effective deterrent against an unattributed nuclear attack and meet the challenges of future threats. This PE is the only DoD research, development, and test and evaluation (RDT&E) program focused on Advanced Component Development and Prototypes for post-detonation NTNF capabilities. Without fully supporting these requirements, the DoD’s ability to meet this critical deterrence need will be significantly degraded. The DoD, through the Innovative Technologies program, will partner with the National Nuclear Security Administration (NNSA) to develop technology aimed at preventing would-be proliferants from advancing nuclear weapons related efforts. Additionally, the DoD seeks to support current and future counterproliferation missions by leveraging the expertise within the national laboratories. The program goal is to ensure DoD's operational units are paired with the NNSA technology experts to develop requirements early in the process to reduce the time of fielding a technology. Nuclear Survivability will invest in innovative radiation hardening techniques to modernize microelectronics for strategic and space systems and increase the reliability of mission critical systems. This program will result in achieving key metrics, including improved understanding of radiation effects on advanced Complementary Metal Oxide Semiconductor (CMOS) technologies; Radiation Hardened/Strategic Radiation Hardened parts qualified and available for space and strategic modernization; Improved mission critical systems reporting; and improved testing procedure guidance for extreme radiation environments.$$, NULL, 42733000, 43339000, 44339000, NULL, NULL, 81, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 62091000, 55308000, 44685000, 44685000, NULL, 44685000, 45232000, $$Nuclear Matters, Advanced Component Development & Prototypes addresses the need to defend and deter against weapons of mass destruction threats and to safeguard personnel, prevent unauthorized access to equipment, installations, material, and documents, and to safeguard the foregoing against espionage, sabotage, damage, and theft. This program oversees advanced engineering development and rapid fielding throughout the Department of War (DoW) for an integrated and systemic approach to develop material solutions. The Physical Security Enterprise and Analysis Program (PSEAP) avoids duplication of effort, ensures systems integration, and promotes interoperability and sustainability. The material solutions either (a) lead to a Program of Record, (b) become technology insertions into existing programs; or (c) advance to being a certified Commercial/Government off-the-shelf product. The PSEAP advances enterprise-level physical security RDT&E solutions to reduce risk created by current and emerging threat by analyzing, researching, developing, demonstrating, and evaluating interoperable solutions to transition capability to warfighters. Collaboration with DoW Components, other government agencies, and the international community to prioritize and close capability gaps is a top priority of the PSEAP and the physical security community. National Technical Nuclear Forensics (NTNF) mission requirements and responsibilities derive from multiple source documents. Per National Security Presidential Memorandum 35 (NSPM 35), the DoW leads the United States (U.S.) Government (USG) post-detonation NTNF capability. NSPM 35 also directs that the US will maintain and advance a robust NTNF capability to detect, identify, locate, and characterize the attribution of the source of an actual or attempted nuclear or radiological attack in all environments, to include underground, underwater, in the atmosphere, and space. Per DoW Directive S-2060.04, the Office of the Undersecretary of War for Acquisition & Sustainment (OUSW(A&S)) is the office responsible for developing and leading the DoW’s NTNF capabilities. Per the 2022 Nuclear Posture Review (NPR) Direction, greater investment in NTNF tools is required to ensure they remain responsive to the threat, and thus scientifically credible and internationally accepted to hold states facilitating acts of nuclear terrorism accountable. The FY 2022 – FY2026 Nuclear Forensics and Attribution Strategic (NFAS) Plan requires an NTNF capability to collect, analyze, and evaluate both air and ground post-nuclear detonation samples at accelerated directed timelines. The DoW mission to collect, analyze, Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                   Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:               PE 0603161D8Z / Nuclear Matters, Advanced Component Development & Prototypes Advanced Component Development & Prototypes (ACD&P) and evaluate post-detonation prompt signals and nuclear debris is critical to our national defense and security to ensuring the USG can identify the source of nuclear material and hold those involved or supporting an attack accountable. Internal and independent assessments indicate that new capabilities are needed to sustain an effective deterrent against an unattributed nuclear attack and meet the challenges of future threats. This PE is the only DoW research, development, and test and evaluation (RDT&E) program focused on Advanced Component Development and Prototypes for post-detonation NTNF capabilities. Without fully supporting these requirements, the DoW’s ability to meet this critical deterrence need will be significantly degraded. The DoW, through the Innovative Technologies program, will partner with the National Nuclear Security Administration (NNSA) to develop technology aimed at preventing would-be proliferants from advancing nuclear weapons related efforts. Additionally, the DoW seeks to support current and future counterproliferation missions by leveraging the expertise within the national laboratories. The program goal is to ensure DoW's operational units are paired with the NNSA technology experts to develop requirements early in the process to reduce the time of fielding a technology. Nuclear Survivability will invest in innovative radiation hardening techniques to modernize microelectronics for strategic and space systems and increase the reliability of mission critical systems. This program will result in achieving key metrics, including improved understanding of radiation effects on advanced Complementary Metal Oxide Semiconductor (CMOS) technologies; Radiation Hardened/Strategic Radiation Hardened parts qualified and available for space and strategic modernization; Improved mission critical systems reporting; and improved testing procedure guidance for extreme radiation environments.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603680S$$, $$Manufacturing Technology Program (ManTech)$$, $$rdte_dw_ba3$$, $$dw$$, 2026, 50610000, 66935000, 100366000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 69, "original_pe": "0603680S", "page_header": "Defense-Wide"}$$::jsonb, $$The Defense Logistics Agency (DLA) Manufacturing Technology (ManTech) Program funds the advanced technology development needed to achieve a responsive and efficient domestic industrial base that meets the warfighters' needs in an affordable and timely manner. The ManTech program works with DLA’s diverse supply chains to improve manufacturing capability throughout a product's life cycle. It provides the crucial link between invention and application by maturing, scaling up, and validating advanced manufacturing technology in “real world” environments. ManTech developments provide a path to low-risk technology implementation for many small businesses and defense unique suppliers as well as depots and shipyards that are critical to DLA. By anticipating and addressing production and sustainment problems before they occur, readiness levels increase, and sustainment costs are decreased. The ManTech R&D Program Element executes from two Lines of Effort (LOEs): Industrial Base and Aging Weapon System Support (IBA), and 3D Technical Data Modernization / Model-Based Enterprise (TDM). These LOEs are closely aligned to documented and tracked priorities specified in the most current DLA Strategic Plan, that calls for Digital Business Transformation as one of three critical capabilities to achieve DLA’s business goals of enhancing performance, reducing costs, and becoming more predictive and data-driven. This critical capability also seeks to transform systems and processes to improve data transparency, reliability, and security for our employees, customers, and suppliers. DLA’s initiatives within this critical capability align with the National Security Strategy (NSS) by emphasizing the importance of harnessing rapid emerging technologies that will transform how we do business. - In addition to alignment with DLA’s top strategic priorities, under Section 2521 of Title 10, US Code, DLA ManTech efforts are collaborated across DOD Military Services and Agencies. As a Principal member of the Joint Defense Manufacturing Technology Panel, DLA’s efforts are integrated within the Joint Defense Priorities. -The IBA LOE seeks to implement innovative and proactive technology solutions to ensure a robust, reliable industrial base that provides affordable and previously hard- to-procure critical parts for DOD weapon systems. This LOE is comprised the following portfolios: DOD Subsistence Supply Chain (Subsistence Network), Castings (Procurement Readiness Optimization Advanced Casting Technology), Forgings (Procurement Readiness Optimization—Forging Advanced System Technology), Batteries (Battery Network), Additive Manufacturing (AM), Advanced Microcircuit Emulation (AME), and Strategic Materials program. -The TDM LOE integrates three-dimensional technical data and knowledge-based tools to transform and streamline supply system responsiveness for DLA-managed commodities. Efforts seek to improve and facilitate the exchange of engineering and logistics information among DLA, the Military Services, DLA industry partners and Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Logistics Agency                                                            Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:             PE 0603680S / Manufacturing Technology Program (ManTech) Advanced Technology Development (ATD) DLA customers. The benefits include shorter product introduction cycles, lower set up-costs for parts production and more economical small batch production. This LOE is comprised of the following portfolios for DOD soldier and individual equipment (Military Unique Sustainment Technology ((MUST)) and Defense Logistics Information Research (DLIR), as well as out of budget cycle or Emerging Requirements (EMR). DLA’s focus for this budget cycle highlights advanced capabilities in digital and technical data modernization, data management and analytics to fulfill the DLA role in the DOD Digital Engineering Strategy and improve sharing of data with the industrial base and supported organizations. Investment explores technologies to lower the Agency’s material acquisition and operation costs and improve weapons systems support. This effort spans across both DLA R&D Program Elements and R&D LOEs, impacting across the DOD Joint Defense Manufacturing Technology Panel and DLA Enterprise logistics processes.$$, NULL, 48834000, 50018000, 51062000, NULL, NULL, 63, $$RDTE_DLA_PB_2026.pdf$$, $$DLA$$, FALSE, 96886000, 176593000, 49787000, 49787000, NULL, 49787000, 52083000, $$The Defense Logistics Agency (DLA) Manufacturing Technology (ManTech) Program funds the advanced technology development needed to achieve a responsive and efficient domestic industrial base that meets the warfighters' needs in an affordable and timely manner. The ManTech program works with DLA’s diverse supply chains to improve manufacturing capability throughout a product's life cycle. It provides the crucial link between invention and application by maturing, scaling up, and validating advanced manufacturing technology in “real world” environments. ManTech developments provide a path to low-risk technology implementation for many small businesses and defense unique suppliers as well as depots and shipyards that are critical to DLA. By anticipating and addressing production and sustainment problems before they occur, readiness levels increase, and sustainment costs are decreased. The ManTech R&D Program Element executes from two Lines of Effort (LOEs): Industrial Base and Aging Weapon System Support (IBA), and 3D Technical Data Modernization / Model-Based Enterprise (TDM). These LOEs are closely aligned to documented and tracked priorities specified in the most current DLA Strategic Plan, that calls for Digital Business Transformation as one of three critical capabilities to achieve DLA’s business goals of enhancing performance, reducing costs, and becoming more predictive and data driven. This critical capability also seeks to transform systems and processes to improve data transparency, reliability, and security for our employees, customers, and suppliers. DLA’s initiatives within this critical capability align with the National Security Strategy (NSS) by emphasizing the importance of harnessing rapid emerging technologies that will transform how we do business. - In addition to alignment with DLA’s top strategic priorities, under Section 2521 of Title 10, US Code, DLA ManTech efforts are collaborated across DoW Military Services and Agencies. As a Principal member of the Joint Defense Manufacturing Technology Panel, DLA’s efforts are integrated within the Joint Defense Priorities. -The IBA LOE seeks to implement innovative and proactive technology solutions to ensure a robust, reliable industrial base that provides affordable and previously hard- to-procure critical parts for DoW weapon systems. This LOE is comprised the following portfolios: DoW Subsistence Supply Chain (Subsistence Network), Castings (Procurement Readiness Optimization Advanced Casting Technology), Forgings (Procurement Readiness Optimization—Forging Advanced System Technology), Batteries (Battery Network), Additive Manufacturing (AM), Advanced Microcircuit Emulation (AME), and Strategic Materials program. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Logistics Agency                                                            Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:             PE 0603680S / Manufacturing Technology Program (ManTech) Advanced Technology Development (ATD) -The TDM LOE integrates three-dimensional technical data and knowledge-based tools to transform and streamline supply system responsiveness for DLA-managed commodities. Efforts seek to improve and facilitate the exchange of engineering and logistics information among DLA, the Military Services, DLA industry partners and DLA customers. The benefits include shorter product introduction cycles, lower set up costs for parts production and more economical small batch production. This LOE is comprised of the following portfolios for DoW soldier and individual equipment (Military Unique Sustainment Technology (MUST)) and Defense Logistics Information Research (DLIR), as well as out of budget cycle or Emerging Requirements (EMR). DLA’s focus for this budget cycle highlights advanced capabilities in digital and technical data modernization, data management and analytics to fulfill the DLA role in the DoW Digital Engineering Strategy and improve sharing of data with the industrial base and supported organizations. Investment explores technologies to lower the Agency’s material acquisition and operation costs and improve weapons systems support. This effort spans across both DLA R&D Program Elements and R&D LOEs, impacting across the DoW Joint Defense Manufacturing Technology Panel and DLA Enterprise logistics processes.$$, $$Budget J-Books/FY27/Remaining/RDTE_DLA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603712S$$, $$Logistics Research and Development Technology (Log R&D)$$, $$rdte_dw_ba3$$, $$dw_dla$$, 2026, 19640000, 16812000, 18543000, NULL, $${"act": "03", "ba_raw": "6.3", "source": "r1_fy26", "service": "dw", "page_num": 69, "original_pe": "0603712S", "page_header": "Defense-Wide"}$$::jsonb, $$The Defense Logistics Agency (DLA) is responsible for providing the Military Services, other Federal Agencies, as well as combined and allied forces, the full spectrum of logistics, acquisition and technical services. DLA acquires, manages and provides virtually 100 percent of the consumable items the military services need to operate – including food, uniforms, fuel and energy, medical supplies, construction and barrier materials, equipment, and more than 85 percent of the military’s spare parts. DLA also provides logistics related services such as logistics information data management, the reutilization of military equipment, as well as document automation and production services. DLA R&D established five Lines of Effort (LOEs) in FY 2023. The Log R&D Program Element executes three LOEs: Logistics Operations Innovation, Predictive Analytics, Modeling & Simulation, and Smart Warehouse Modernization. The DLA Manufacturing Technology Program (PE 0603680S) executes two LOEs: Industrial Base and Aging weapon Systems Support and 3DTechnical Data Modernization/Model Based Enterprise. The Log R&D program helps ensure that advanced logistics concepts and business processes are used to accomplish the agency’s mission with the leanest possible infrastructure. Log R&D identifies the best commercial business practices and tailors them, as necessary, into the most effective business processes for the agency. Log R&D develops and demonstrates high risk, high payoff technology that provides a significantly higher level of support at the lowest possible costs. The LOEs are closely aligned to priorities specified in the most current DLA Strategic Plan, which identifies Digital Business Transformation as one of three critical capabilities to achieve DLA’s business goals of enhancing performance, reducing costs, and becoming more predictive and data driven. This critical capability also seeks to transform systems and processes to improve data transparency, reliability, and security for our employees, customers, and suppliers. DLA’s initiatives within this critical capability align with the National Security Strategy (NSS) by emphasizing the importance of harnessing rapid emerging technologies that will transform how DLA does business. - Logistics Operations Innovation: R&D efforts to cultivate integration of innovative processes and technology into the DLA supply chains to enhance warfighter readiness and weapons system sustainment. This LOE focuses on supporting the DLA LOE 4: Modernized Acquisition and Supply Chain Management, while also investment in cross-cutting supply chain efforts, to include fuel quality and alternative fuel sources, and emergent needs that impact DLA’s ability to effectively support the warfighter through the following portfolios: Energy Readiness Program (ERP), Acquisition Modernization Technology Research (AMTR), and Supply Chain Management and Sustainability (SCMS). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Logistics Agency                                                            Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:             PE 0603712S / Logistics Research and Development Technology (Log R&D) Advanced Technology Development (ATD) - Predictive Analytics, Modeling & Simulation: R&D efforts develop predictive analytic solutions using data and Artificial Intelligence/Machine Learning (AI/ ML) to solve high-impact problems, improve business operations, and provide actionable strategies to inform business decisions. Primarily focused on the DLA Strategic Plan Critical Capability C: Digital Business Transformation, these LOE efforts cut across DLA Strategic Plan LOE 1: Warfighter Always, LOE2: Trusted Mission Partner, and LOE 4: Modernized Acquisition and Supply Chain Management, supporting the warfighter through the Logistics Technology Research (LTR) portfolio of projects. - Smart Warehouse Modernization: R&D efforts to modernize distribution and disposition operations through infusion of smart-warehousing, interconnected technologies, and automation. This LOE is dedicated to one of the primary focus areas of DLA’s Critical Capability for Digital Business Transformation: warehousing modernization through efforts within the Strategic Distribution and Disposition (SDD) portfolio of projects. DLA’s focus for this budget cycle highlights advanced capabilities in digital and technical data modernization, management and analytics to transform DLA Business Processes to lower the Agency’s material acquisition and operation costs along with improving weapons systems support.$$, NULL, 19210000, 19618000, 19979000, NULL, NULL, 64, $$RDTE_DLA_PB_2026.pdf$$, $$DLA$$, FALSE, 17900000, 23640000, 18791000, 18791000, NULL, 18791000, 20378000, $$The Defense Logistics Agency (DLA) is responsible for providing the Military Services, other Federal Agencies, as well as combined and allied forces, the full spectrum of logistics, acquisition and technical services. DLA acquires, manages and provides virtually 100 percent of the consumable 