INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1160490BB$$, $$Operational Enhancements Intelligence$$, $$rdte_dw_ba7$$, $$dw_socom$$, 2026, 21752000, 18249000, 27233000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 81, "original_pe": "1160490BB", "page_header": "Defense-Wide"}$$::jsonb, $$This project is part of the Military Intelligence Program. This project is reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program Annual Report to Congress.$$, NULL, 25151000, 23377000, 22246000, NULL, NULL, 297, $$RDTE_SOCOM_PB_2026.pdf$$, $$SOCOM$$, FALSE, 27233000, 41752000, 25747000, 25747000, NULL, 25747000, 22141000, $$This project is part of the Military Intelligence Program. This project is reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program Annual Report to Congress.$$, $$Budget J-Books/FY27/Remaining/RDTE_SOCOM_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604874C$$, $$Improved Homeland Defense Interceptors$$, $$rdte_dw_ba4$$, $$dw_mda$$, 2026, 1637414000, 2073886000, 1670256000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 73, "original_pe": "0604874C", "page_header": "Defense-Wide"}$$::jsonb, $$The Improved Homeland Defense Interceptors provides the development, integration, and testing of a Next Generation Interceptor AUR consisting of an integrated boost vehicle/multiple kill vehicle payload capable of surviving both natural and hostile environments while countering the allocated threat space. Meeting the United States Northern Command's (USNORTHCOM) Operational Needs for Homeland Defense. The Next Generation Interceptor will provide USNORTHCOM a solution that is lethal across the specified threat space; upgradeable to address future and advancing threats; and fully integrated into the Ground-Based Midcourse Defense (GMD) Weapon System (GWS). The Missile Defense Agency (MDA) issued a Request for Proposal in FY 2020 and competitively awarded two best value contracts on March 24, 2021, for a Next Generation Interceptor acquisition. The MDA maintained the competitive environment through Preliminary Design Reviews (PDR) and Knowledge Point (KP) 1 in FY 2024 to reduce technical risk, encourage schedule acceleration, and support the Department's ability to field a system capable of negating the expanding threat. With the PDR/KP #1 data, the MDA selected a single Prime contractor for continued development through a CDR; qualification; integration with the GWS; ground cyber and flight testing; and AUR production. Rapidly evolving rogue and peer missile threats have led to a change in national defense policy. The President's January 27, 2025, Executive Order established a goal of protecting the United States (U.S.) citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. The MDA is responding with speed and intensity to deliver next-generation missile defenses to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats. This program submission reflects changes necessary to meet this evolving mission space. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Missile Defense Agency                                                              Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:            PE 0604874C / Improved Homeland Defense Interceptors Advanced Component Development & Prototypes (ACD&P)$$, NULL, 1859835000, 1425260000, 1162687000, NULL, NULL, 123, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 1619530000, 1510505000, 1344824000, 1344824000, NULL, 1344824000, 724921000, $$The Improved Homeland Defense Interceptors PE provides the development, integration, and testing of a Next Generation Interceptor AUR, consisting of an integrated boost vehicle/multiple kill vehicle payload capable of surviving both natural and hostile environments while countering the allocated threat space to meet the United States Northern Command's (USNORTHCOM) Operational Needs for Homeland Defense. The Next Generation Interceptor will provide USNORTHCOM a solution that is lethal across the specified threat space, upgradeable to address future and advancing threats, and fully integrated into the Ground-Based Midcourse Defense Weapon System (GWS). The Missile Defense Agency (MDA) issued a Request for Proposal in FY 2020 and competitively awarded two best value contracts on March 24, 2021, for a Next Generation Interceptor acquisition. The MDA maintained the competitive environment through Preliminary Design Reviews (PDR) and Knowledge Point (KP) #1 in FY 2024 to reduce technical risk, encourage schedule acceleration, and support the Department's ability to field a system capable of negating the expanding threat. With the PDR/KP #1 data, the MDA selected a single Prime contractor for continued development through a CDR, qualification, integration with the GWS, ground cyber and flight testing, and AUR production. The funds requested in this PE provide both legacy and Global Missile Defense Capability development for the United States, its deployed forces, allies, and partners. The capabilities funded by this budget request are complementary to the architecture funded by the Golden Dome Program's separate budget request and together fulfill the President's Executive Order 14186. The President's January 27, 2025, Executive Order established a goal of protecting the U.S. citizens, safeguarding critical infrastructure, and securing second-strike capability against missile attack from any adversary. This program and budget in addition to the budget requested by the Golden Dome Program Office reflects the changes necessary to protect the U.S. against ballistic, hypersonic, cruise, and other advanced missile threats. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Missile Defense Agency                                                        Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:          PE 0604874C / Improved Homeland Defense Interceptors Advanced Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
